insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2018-01-25','Correo-e. CRPS-Zafra: Buenos días, mi nombre es Mª del Cielo Esteban Reyes, Trabajadora social del CRPS Zafra (Telefono: 924 555 943, Email:crps_zafra@hotmail.com),me pongo en contacto con usted en relación a Beatriz Mejías de la MOrena, paciente del CRPS y tutelada por ustedes. Actualmente Beatriz estaba viviendo de manera autónoma y sola con la supervision del CRPS, pero desde hace unos días ha decidido convivir con su pareja, por lo que desde el Centro se ha decidido ponerlo en conocimiento de la Comisión para que lo tengan en cuenta. Si necesitan alguna otra información, ruego se pongan en contacto con nosotros. Sin más, reciba un cordial salud. Mª del Cielo Esteban Reyes TRabajadora Social del CRPS DE ZAFRA C/ Vicente Cervantes, 2 06300 Zafra (Badajoz) +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Mª del Cielo. +++Llevan una relación desde hace 2 años con muchos altibajos, cortando y volviendo en sucesivas ocasiones."No sé cuánto durará esta vez..." El día 15 estuvimos con ella en el Juzgado (CTAEX) y no comentó nada sobre esta convivencia. +++Confrimará tratamineto anticonceptivo. +++Informarán de cualquier incidencia.','2');
