insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-01-30','-AMALIA: LLAMA POR TF. LA TS. DEL CTRO DE SALUD DE ZAFRA (45970) CON EMAIL: maria.zapatac@salud-juntaex.es. NOS COMUNICA QUE ATI HA ESTADO POR ALLÍ , QUE ESTÁ CON CONSUMO ACTIVO DE DROGAS Y QUE ESTÁ DURMIENDO EN LA CALLE PQ TODO EL DINERO LO GASTA EN ESO. TIENE PLEITOS CON FAMILIA Y VECINOS EN EL JUZGADO , MAÑANA CREE QUE ES LA CITACIÓN Y LUEGO SE VENDRIA AL CTRO. HNO. DE MÉRIDA. A NIVEL PSIQUIATRICO SE ESTÁ PONIENDO EL INYECTABLE Y NO ESTÁ DESCOMPENSADO , HA ESTADO HACE UN PAR DE SEMANAS INGRESADO EN LA UHB DE LLERENA. QUIEREN QUE SE LE AMPLIE LA INCAPACIDAD, ENVIARÁN INFORMES MEDICOS Y SOCIALES PARA QUE SE SOLIICITE DESDE AQUI. SOLICITO DERIVACIÓN DE SU PSIQUIATRA A COMUNIDAD TERAPEUTICA Y VAN A COMENTARLO CON SU PSIQUIATRA. SOLICITO A LA PARTE EC. QUE SE SOLICITE AL BANCO QUE NO SE LE DE ADELANTOS ECONOMICOS. HAY QUE LIMITAR LA CUENTA , QUEDAMOS PENDIENTE DE SU VISITA Y DE LOS CAMBIOS DE DOMICILIO PARA ELLO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='MORENO'and apellido2='MOYANO'),'2018-01-30','-AMALIA: NOS LLAMA POR TF. PARA COMUNICAR QUE LE HAN ROBADO SU TARJETA BANCARIA Y LE HAN SACADO MIL €. COMPROBAMOS EN SU CUENTA , QUE HAN SIDO DOS REINTEGROS Y EN LA MISMA OFICINA DONDE ÉL ACUDE. AL RATO VUELVO A LLAMARLO PARA INTENTAR SACARLE LA VERDAD DEL ASUNTO PERO NO CUENTA NADA. NO QUIERE DENUNCIAR E INSISTE QUE NO HA SIDO ÉL . LE HAN DADO UN Nº PIN NUEVO , HAY QUE CAMBIAR TB LA TARJETA ??','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2018-01-30','(Pedro) Llamada de Olga Rubio, T. Soc. del C. de Salud-Plasencia III. (74523). +++D. Domingo diagnósticado de cáncer (¿pulmón?) con metástasis. Probablemente pase a cuidados paliativos. +++En estos momento, no daría puntuación para plaza sociosanitaria, pero dado que no puede seguir proporcionando el apoyo necesario en la vivienda y no quiere ir a ninguna residencia, se plante la siguinete ALTERNATIVA: AMPLIAR LA AYUDA A DOMICILIO QUE RECIBE, a efectos de cubrir las tareas domésticas de una forma más adecuada.','2');
