insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='FERNANDEZ'and apellido2='MUÑOZ'),'2018-01-31','(Pedro)Llama Ana (630-346052), hermana de Dª Concepción. +++Se llevarán a su hermana a pasar el fin de semana con ellos. +++Enviarán documento con persona responsable, DNI, dirección y teléfono de contacto. +++Pregunta quién tendría que solicitar la manutención para la hija de Concepción, que vive con su padre: entendemos que ha de ser el padre el que lo haga.','2');
