insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='RODRIGUEZ'and apellido2='GRAGERA'),'2018-01-31','(Pedro)INCIDENCIA: +++ Ayer, sobre las 15:20, tras salir del trabajo encontré a Dª Luisa circulando por el arcén de la rotonda de la Consejería de Agricultura, dirección Badajoz, con riesgo de atropello. Según dijo, venía de ponerse la inyección y estaba completamente desoirientada, tanto en el espacio como en su discurso. En un primer momento, no me conoció -"¿quién eres...?- Cuando le dije que era Pedro me reconoció y no puso pega alguna cuando le pedí que entrase en el coche para llevarla al CRR, trayecto durante el cual no paró de hablar de manera compulsiva y poco inteligible. En el CRR la dejé con Javier Pecero, quien salía en ese instante supongo que para su casa (eran las 15:45 aproximadamente).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='MARQUEZ'and apellido2='ANDRADE'),'2018-01-31','Icíar: Llaman de Asindi(t/c 927 39 09 74) para saber si el ingreso de Victoria en La Providencia se ha realizado ya pues tienen allí sus enseres que puede necesitar. Han estado mirando presupuestos para el envío y rondaría los 100€, nos lo enviará. Quedo en avisarles cuando Victoria ingrese.','2');
