insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2018-02-01','-AMALIA: LLAMA LA TS DEL C.SALUD DE PLASENCIA ( OLAG 74852) PARA INFORMAR DE LA SITUACION SANITARIA DE DOMINGO , ESPOSO DE NUESTRA TUTELDA. ES GRAVE Y ESTÁ RECIBIENDO CUIDADOS PALIAIVOS EN DOMICILIO. QUIERE SABER SI PODEMOS CONTRATAR UNAS HORAS MÁS DE S.A.D. PARA AYUDAR A LA PAREJA. CONFIRMO QUE TIENE DINERO AHORRADO Y LE PIDO A FUTUEX QUE NOS ENVIEN PRESUPUESTOS POR HORAS . EN LA CASA HAY 5 PERROS , EL HIJO QUE ES DUEÑO DE 2 NO LOS ATIENDE NI BUSCA ALTERNATIVA . INSISTO EN BUSCAR SOLUCIÓN PARA SACAR A LOS PERROS DEL DOMICILIO.','2');
