insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2018-02-01','(Pedro). TRASLADO de Margarita, en el día de hoy (01 de FEBRERO de 2018), desde el centro "Las Cumbres" al CSS de Plasencia. +++En todo momento se mostró tranquila y alegre al ver que regresaba a su tierra: cuando entró en Extremadura empezó a cantar el himno.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2018-02-01','(Pedro). Se realiza el TRASLADO de D. Francisco al CSS de Mérida. SE solicitó a la Audiencia Provincial de Mérida acompañamineto por parte de la Guardia Civil. +++Sin incidentes en el traslado. +++Comineza en el día de hoy (01 de FEBERERO DE 2018) la EJECUTORIA 54/2017 dictada por la Audiencia Provincial sección 3, de Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='CUEVAS'and apellido2='LOPEZ'),'2018-02-02','INGRESO EN CENTRO El 01/02/2018. "Se comunica a esa Comisión Tutelar de Adultos que Francisco..., tutelado por esa Comisión, ingresa en este Centro Sociosanitario de MÉRIDA en fecha 01/02/2018 para cumplimiento medida de seguridad de internamiento. (Audiencia Provincial nº 3 de Mérida. Rollo: EJE EJECUTORIA 54/17)."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CONCEPCION'and edp.apellido1='CANELADA'and apellido2='GARCIA'),'2018-02-02','(Pedro). Gemma, T. Social de "El Cuartillo".(22163). +++Dª Concepción insiste en marcharse a su casa con su marido. +++Posible influencia en ello de las visitas que recibe de su marido e hijo, habiéndole prohibido a éste el acceso a las habitaciones y con cierta "supervisión" discreta de las visitas a su mujer. +++Se le informa de que , en caso necesario, nos pueden solicitar autorización para restringir y, llegado el caso, suprimir dichas visitas o autorizar que estas sean con supervisión directa. +++En caso de conflicto con el mariudo o cualquier otros familiar activar 112 o policía directamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2018-02-02','(Pedro). +++Ayer estuvieron en la Comisión la madre y hermano de Ramón. Pedían su pensión porque iba a salir del 01 al 05 de febrero para estar con ellos. +++CONVESRACIÓN CON MARIBEL, T. Soc. del CSS de Mérida (24013): +++Para esta salida se le han dado los 3€/día que se le dan en el Centro, más 100 € para tabaco.No se han tenido en cuenta los gastos en alimewntación. Si los piden, hablar con el CSS para que lo tengan en cuenta para futuras salidas (la cantidad que se estime oportuna por día). +++En la salida de Navidad se le dieron, desde el CSS, además de la ropa que se le compró, 60€/gasolina para el viaje (SE LES DA CADA VEZ QUE VAN A VISITAR A RAMÓN), y 80€ más. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamada a Juan (634-703501), hermano de Ramón. +++Solicita saber qué pensión tiene su hermano para que pueda ayudar a su madre que necesita mucho el dinero. Se le explica el por qué no se pueden dar esos datos y que tampoco esd posible entregar a su madre una parte del din ero de Ramón porque es el único dinero del que dispone la Comisión para afrontar los gastos futuros de su hermano. +++Alega que solamente para ir a verlo se gastan mucho dinero, pero reconoce, cuando se le expone, que dichos desplazaminetos se le están abonando desde el CSS a razón de 60€/viaje.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOAQUIN'and edp.apellido1='GONZALEZ'and apellido2='MILLON'),'2018-02-02','Iciar: Se solicita por correo con Acuse al INSS el certificado de pensión familiar con hijo a cargo a petición del centro para solicitar la tarjeta de transporte subvencionado.','2');
