insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ELIAS'and edp.apellido1='MACHIO'and apellido2='FLORIDO'),'2018-02-02','La dirección de la residencia comunica que D. Elías fue dado de alta la semana pasada. Trato de hablar con Petri (Directora) pero está ocupada en este momento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2018-02-02','Juzgado de 1ª Instancia e Instrucción de Cáceres. SEntencia Nº 12/2018, de 24 de enero. +++Se absuekve a Dª Luisa de los cargos "...que se le pudiere haber imputado..."','2');
