insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BARTOLOME'and edp.apellido1='ALBA'and apellido2='GRAGERA'),'2018-02-02','En relación con la modificación de la incapacitación de Bartolomé, el CSM de Montijo, tras hablar con Elena, intentará encviarnos Informe Psiquiátrico el lunes. En cuanto al Juzgado, enviamos Fax comunicando que con motivo de este procedimiento, estamos a la espera de recibir el Informe Psiquiátrico y que lo enviaremos a Gabinete Jurídico cuando dispongamos de él, a los efectos de solicitar la modificación de la incapacitación y como medida cautelar, su ingreso involuntario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIANO'and edp.apellido1='GARCIA'and apellido2='GARRIDO'),'2018-02-04','INGRESO El 04/02/2018. "Se comunica a esa Comisión Tutelar de Adultos que el interno Luciano..., ingresado en este Centro y tutelado por esa Comisión, será trasladado al Hospital de Mérida, en fecha 04/02/2018."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUCIANO'and edp.apellido1='GARCIA'and apellido2='GARRIDO'),'2018-02-05','PIA Se remite Revisión de PIA a la G.T. de Cáceres. Sección Plasencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2018-02-05','Iciar: Llama Casiano Poderoso,t/c 659 08 22 67, el suegro de Feliciano, nos solicita un documento de cesión de la parcela a cambio del mantenimiento de la finca para que pueda pedir el permiso al Ayto para la limpieza de las encinas,( entran jabalíes a comer las bellotas, y puede producirse un fuego debido a los arbustos) El periodo para pedir el permiso concluye a finales de mes','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='SOFIA FLORENTINA'and edp.apellido1='COLLADO'and apellido2='ESTEBAN'),'2018-02-05','(Pedro). Conversación con José tello, en relación con la finca (olivar) de Dª Sofía: +++Plantea autorice el Juzgado la realización de la herencia solo sobre dicha finca. +++Queda abierta la posibilidad de arrendamiento por aprovechamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2018-02-05','(Pedro). +++Se envía al CSS de Plasencia escrito de contestación para remitir al Juzgado de 1ª instancia nº 3 de Plasencia, argumentando los motivos del traslado de Margarita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='PEREO'and apellido2='REBOLLO'),'2018-02-05','(Pedro). Visita de D. Antonio a la CTAEx. +++SE HA FUGADO del CSS. +++Ha venido a la CTAEx para hblar conmigo. Le ha atendido Amalia, quien ha avisado al CSS. +++Ha vuelto a venir con un taxista al que hemos pedido que lo llevase al CSS. +++Refiere que quiere ir a ver a su madre a "Felipe Trigo" porque está muy enferma.Y que quiere arreglarse la boca (pero no tiene dinero). +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Maribel, T. Soc. del CSS: +++No es verdad lo de su madre. Cada vez que ella quiere verlo llaman de la Residencia y la va a ver acompañado de su hermana, con lo que ahora no se lleva bien. +++En cuanto a la dentadura "...si no se hubiese gastado el dienro cuando salía con su hermana ahora podría tener la dentadura puesta. +++Ya se ha dado parte al Juzgado de la fuga. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Llamo al CSS: me confirman el regreso de D. Antonio a las 14:55h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2018-02-06','Enviamos al abogado de oficio, José Luis Malpartida Villegas, 927217594-649647383, documentación relacionada con la solicitud de modificación de medidas, con motivo de la pensión de alimentos de 200 euros/mes, que paga a su exmujer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-02-06','(Pedro) Intento llamar a Ildefonso al teléfono que nos consta: 625-245891. Da llamada pero a la tercera se corta. En segundo intento el contestador informa de que las llamadas entrantes están restringidas (en llamadas anteriores también se reproducía este mensaje). ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro) Conveeración con María, T. Soc. del C. Salud. +++Ildefonso lleva dos días sin aparecer por allí: no quiere que nadie le controle en ningún sentido. +++El Psiquiatra considera que está estable psicopatológicamente, por lo que no se considera la derivación a UHB. +++Han enviado Informe de situación, planteando la posibilidad de solicitar la ampliación de la incapacidad. No ha llegado todavía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2018-02-06','-AMALIA: ENVIO SOLICITUD DE DEPENDENCIA Y SOLICITD REVISION GRADO DISCAPACIDADA A MARIVI CLEMENTE ( ESTA EN LARGA ESTANCIA ) PARA QUE AÑADA I.MEDICOS Y LO REGISTRE DESDE ALLI.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2018-02-07','(Pedro)Conversación con Soraya Directora CSS Plasencia (24104): +++Margarita se está adaptando muy bien. Van a valorarla lo antes posible para que pueda empezar con los talleres y se están planteando la posibilidad de empezar a dejarla salir con compañía.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='FAUS'and apellido2='LEMUS'),'2018-02-07','-AMALIA: HABLO CON PATRICIA DEL CTRO PENIT. PARA CONFIRMAR DONDE SE ENCUENTRA RAFAEL . CONFIRMAMOS QUE SIGUE EN CASA DE SU TIA ASUNCION. SU HERMANO JUAN DE DIOS HA SALIDO DE LA CARCEL Y TB SE VA A CASA DE LA TIA , LAS PNC DE AMBOS SE VAN A VER DISMINUIDAS. - LA TIA QUIERE CONCERTAR CITA PARA HABLAR SOBRE RAFAEL . -DE PNC NOS PIDEN UN CDO. COMO QUE ESTÁ EN SU DOMICILIO Y LA AUTORIZACIÓN DE CONSULTA A FICHEROS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DOMINGUEZ'and apellido2='GARCIA'),'2018-02-07','(Pedro)Conversación con Mamen (Dependencia III). +++Grado I. Valoración realizada el 21-11-2016.PIA posible SAD: si no se quiere dejar la Residencia renunciar a él. +++Planteo hablar con la Residencia para valorar si pudiese haber habido un empeoramiento del estado de salud de D. Rafael, susceptible de solicitar revisión de grado. Una vez realizado este contacto, volver a hablar con Mamen.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2018-02-07','(Pedro). Conversación con Soraya (CSS Plasencia): +++Margarita quiere hablar contigo. Quedamos en que la llamaré hoy a las 13:30. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Margarita: +++"Estoy muy contenta aquí y quiero pedirte solamente dos cosas: si me puedo quedar aquí hasta el verano, porque se van a ir de vacaciones a la playa y me quiero ir con mis amigas y si no te importa decirme el nombre de tu mujer y el tuyo -¿por qué?- porque os quiero hacer un regalo -no es necsario- sí, sí, ya verás como os gusta..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2018-02-08','En relación con el juicio verbal 684/2017, por el accidente que tuvo con el repartidor de burger king, se ha dictado Sentencia nº 32/2018, por el JUzgado de Primera Instancia nº 2, de Badajoz. La estiman parcialmente y condenan a pagar a Daniel a la cantidad de 884,40 euros, en lugar de los 1.597,20 euros que pedía la parte demandante. Una vez se dicte la Ejecutoria, procederemos al pago.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ISABEL'and edp.apellido1='VALADES'and apellido2='DIAZ'),'2018-02-08','(Pedro)Llamada de Isabel Valadés (627-129372). +++Solicita 50€ de extra para compar ropa en las rebajas. +++Consultada la parte económica, se autoriza extra de 50€ para mañana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2018-02-08','(Pedro)Conversación con Julián Álvarez, Geremte Cocemfe-Cáceres (927-239028 y 654-181964). +++Tomás está INGRESADO EN UCI desde el pasado martes por una SEPTICEMIA. +++ El lunes le cambiaron la sonda y el martes por la mañana empezó a sangrar con profusión. SE le llevó a Urgencias donde le hicieron un primer tratamineto pero al ver que no reaccionaba lo ingresaron en UCI, dado que su estado ha llegado a ser bastante grave. Ayer estaba más estable y hoy sigue en la UCI, con previsión de pasarlo a planta según su evolución. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con José Mª Tovar: +++EN DESACUERDO COMPLETAMENTE CON EL TRATAMIENTO DE LA SITUACIÓN EN LA QUE SE ENCUENTRA TOMÁS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA TERESA'and edp.apellido1='NEVADO'and apellido2='MARTIN'),'2018-02-08','Envío email al abogado Luis Balanzategui Nogales (646067171), en relación con la solicitud de autorización de aceptar herencia y venta de inmueble.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DOMINGUEZ'and apellido2='GARCIA'),'2018-02-08','(Pedro) Conversación con Dolores, T. Soc. SSB de Medina de la Torres (924-560412). +++Plantea empeoramineto de la situación de D. Rafael. +++Solicitamos Informe Médico para pedir Revisión de Grado en cuanto se nos envíe. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conveeración con Mamen (Técnico PIA): +++Enviaría resolcuión PIA SAD para su no aceptación y mantener la plaza residencial actual. Por otro lado, pedrimos revisión PIA .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIANA PAULA'and edp.apellido1='CENTENO'and apellido2='RODRIGUEZ'),'2018-02-08','Iciar: hablamos con Pilar Cerrillo t7c 618908506, para acordar hora en la Residencia para llevarle los ensres que nos han solicitado para Juliana. Nos llama la vecina de abajo del piso para comunicarnos que tiene humedades en la cocina que deben de provenir del piso de arriba, el de Juliana, a pesar de que en su día cortamos el agua pero ella dice que las tuberías son muy antiguas. Llamo a Felicidad, la propietaria al fijo y móvil, no contesta, le envío correo electrónico para que quede con su seguro, si puede ser mañana día 9/2/18 que es cuando voy a ir con la compañera de futuex al piso de Juliana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2018-02-08','-AMALIA : NOS EMITEN DESDE PNC LA OPCION , LO PONGO PARA FIRMA DE LA GERENTE Y UNA VEZ FIRMADO HAY QUE ENVIARLO A COCEMFE PQ TIENE QUE FIRMAR TB TOMAS. DESDE ALLÍ QUE LO REGISTREN PARA PNC Y NOS EMITAN UNA COPIA .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CEFERINO'and edp.apellido1='MARISCAL'and apellido2='CRESPO'),'2018-02-08','-AMALIA: RECIBIMOS INFORME DEL CRR BADAJOZ PARA LA DECLARACION ANUAL PERO VIENE SIN FIRMAR. LES PIDO QUE VUELVAN A REMITIRLO FIRMADO. SIGUE INSISTIENDO EN IRSE DE BADAJOZ, YA SE PRESENTÓ LA SOLICITUD DE TRASLADO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DOLORES'and edp.apellido1='PESADO'and apellido2='ESTEBAN'),'2018-02-08','-AMALIA: SE RECIBE UNA COMUNICACION DE DEPENDENCIA PLASENCIA , INDICAN QUE SE LE OFRECIÓ LA P.EC.VINCULADA A SAD Y LA POSIBILIDAD DE SOLICITAR SERVICIO ATENCION RESIDENCIAL DE DISCAPACIDAD , EN UNA VISITA DEL 17/12/2017. TANTO DOLORES COMO SU HNO. RECHAZAN EL INGRESO CON LO QUE EL EXPEDIENTE SE CIERRA CON LA VINCULADA A SAD. - CUANDO NOS DEN LA TUTELA SERÍA CONVENIENTE QUE LA VISITARAN DESDE FUTUEX PARA VALORAR ESTE INGRESO Y PROCEDERIAMOS A SOLICITARLO DE FORMA INVOLUNTARIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO MANUEL'and edp.apellido1='ALVAREZ'and apellido2='HIDALGO'),'2018-02-09','-AMALIA: HABLO CON ALICIA ( TECNICO PIA DEPEND. AZUAGA) SE SOLICITÓ UNA REVISION PIA . ACTUALMENTE PERCIBEN P.ENTORNO A FAVOR DE LA MADRE . NO SE ESTAN GARANTIZANDO CUIDADOS : CASA EN MALAS CONDICIONES, NO MEDICACIÓN.. ALTERNATIVAS POSIBLES : P.VINCULADA PARA SAD, C.DIA , C.OCUPACIONAL , INGRESO EN CENTRO . SOLICITO A FUTUEX UNA VISITA CONJUNTA CON LA TS DEL SSB DE VALENCIA DEL VENTOSO PARA BUSCAR LA VOLUNTARIEDAD DEL TUTELADO , NO NOS SIRVE DE NADA ACEPTAR SAD SI LUEGO NO VAN A DEJARLE ENTRAR EN EL DOMICILIO . SI NO ACEPTAN NADA HABRIA QUE VALORAR LA OPCION DE INT. INVOLUNT . QUEDO PTE. DE LA VALORACION DE FUTUEX Y CONTESTAR A DEPENDENCIA CON LA ALTERNATIVA ELEGIDA AL TF 20783','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2018-02-09','(Pedro). Reunión con la Unidad de Salud Mental y la Subdirección de Salud mental.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ABEL'and edp.apellido1='PEREZ'and apellido2='GARRIDO'),'2018-02-09','-AMALIA: HE HABLADO CON TANIA ( TS DEL CEDEX Y ESM ) , CON SU PADRE ( FELIX PEREZ 652319728) Y CON MAYTE DEL CENTRO DE INTEGRACION SOCIAL DE CACERES ( 927301309) , GESTIONA TEMAS JUDICIALES . TODOS ESTÁN DESEOSOS DE QUE COGAMOS LA TUTELA PQ NO SABEN QUÉ HACER CON ESTE CASO. HA ESTAADO 5 AÑOS EN LA CARCEL , CONSUME DROGAS , TIENE DISCAPACIDAD PSQUICA Y FISICA Y JUICIOS JUDICIALES PENDIENTES. ACTUALMENTE EN LIBERTAD VIGILADA . NO PUEDE INGRESAR EN CC. TERAPEUTICA DROGAS POR SU DETERIORO COGNITIVO , Y POR LO TANTO TAMPOCO PODRIA INGRESAR EN OTRO RECURSO POR SU CONSUMO ACTIVO . CREEN QUE SI LO TUTELAMOS LO INGRESAREMOS Y LES INFORMO DE NUESTRAS LIMITACIONES. VA A SOLICITAR AL JUEZ DE PENAL QUE LE REVOQUE LA LIBERTADAD CONDICIONAL Y LO INGRESE EN CENTRO PENITENCIARIO PSIQUIATRICO O EN C.PENITENCI Y DESDE ALLI QUE LO VALOREN Y DERIVEN AL OTRO . YA ESTARÍA REVOCADA PERO LA GUARDIA CIVIL EMITIÓ INFORME DESFAROBLA A SU INGRESO POR SU ESTADO DE SALUD.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2018-02-09','-AMALIA : ME LLAMA PAULA DEL CRR PLASENCIA (677407893) PARA VER SI SE HABIA PEDIDO PLAZA RESIDENCIAL PARA GUADALUPE. CONFIRMADO CON MAYORES QUE NO ESTÁ PEDIDA. TIENE POR DEPEND. G.II N.1 . HAY QUE SOLICITAR REVISION PIA Y SOLIICTAR RESIDENCIA DE MAYORES Y REVISION GRADO POR EMPEORAMIENTO PARA VER SI SUBE A G. III Y TENDRÍA PREFERENCIA EN EL ACCESO. CUMPLE PERFIL , YA TIENE 64 AÑOS Y ENFERMEDADES QUE DIFICULTA SU CONTINUIDAD EN CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2018-02-09','- PIDO AL CENTRO INFORMES MEDICOS ACTUALIZADOS PARA SOLICITAR REVISION GRADO DEPEN. PENDIENTE DE RECIBIRLOS PARA HACERLO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2018-02-09','-AMALIA: HABLO CON MARIVI ( CSS PLASEN) EL LUNES SE TRASLADA A JUAN CHAMORO AL CRR DE MERIDA EN TAXI ( NOS ENVIARAÁ LA FACTURA) DE CRR SE PREVEE UNA ESTANCIA DE UNOS DIAS PARA PASAR A LOS PISOS SUPERVISADOS TB EN MERIDA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2018-02-09','(Pedro) Llamada de María Rapado, de Caser Residencial Olivenza (924-492890). Director Adolfo Gordillo. +++CONVOCADA reunión para el martes 20 de febrero en la Comisión, a las 9:30h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2018-02-09','(Pedro) Conversación con Julián. +++En el momento de la llamada estaba con Tomás, quien estaba comiendo. +++Ya lo pasan a la 8ª planta, a la Unidad de Urología. +++Se prevé acompañamiento sin determinar por el momento el tiempo necsario para ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GERMAN JOSE'and edp.apellido1='MONTERO'and apellido2='MORENO'),'2018-02-09','-AMALIA: HABLO CON ANGELA ( TS PLACEAT ) ME COMENTA SOBRE LA SITUACION FAMILIAR DE GERMAN. TIENE SU TARJETA SANITARIA NO SE LA QUIERE DAR PQ SIEMPRE LA PIEDEN . NO LE FACILITA SU DNI PARA ESCANERARLO ( LO NECESITAN PARA ABRIR LA CUENTA ) . VOY A PEDIR A FUTUEX QUE LO VISITEN , QUE QUEDEN CON LAS TS DEL SSB PARA VALORAR POSIBLE INGRESO EN CENTRO . LA MADRE SE NIEGA TENDRIAMOS QUE PEDIR LA AUTORIZACION JUDICIAL . TIENEN SAD MUNICIPAL DIARIO . LE HAN CITADO PARA UN TTO. DE RADIACIÓN , PERO NO ES POSIBLE MIENTRAS CONTINUE EN CASA GARANTIZAR LOS CUIDADOS NECESARIOS TRAS RECIBIR ESTA RADIACIÓN . HAY QUE PEDIRLE PNC +CPTO . TIENE PFHC CON CPTO SUSPENDIDA , EL TITULAR ES EL PADRE. ESTOY PENDIENTE DE LA CUENTA PARA GESTIONAR LA PNC.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='CALZAS'and apellido2='SANCHEZ'),'2018-02-09','-AMALIA: SOLIICTO A FUTUEX QUE CONTINUE LAS VISITAS EN DOMICILIO , CUANDO ME CONFIRMEN QUE HAN SACADO A LOS PERROS SOLICITARÉ A LA EMPESA SAD AUMENTO A 3 HORAS .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-02-12','(Pedro). Conversación con Mercedes, T. Social Plena Inclusión (Llerena) (924-871037): +++Proceso de adaptación sigue siendo muy bueno. +++En las dos últimas semanas Beatriz insiste más en ver a Rocío. +++Su padre ha solicitado que vaya a casa a pasar un fin de semnana con él. En el centro lo ven precipitado dadas las circunstancias. +++Desde Comisión nos pondremos en contacto con D. G. Infancia y Familia para saber en qué punto se encuentra el expediente de acogimiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2018-02-14','Visita de Ramón a la Comisión: +++Quiere marcharse un mes con su hermana Mª Luisa (688-283599 y 634-740177) a Valencia para despejarse. Su hermano Luis se quedaría con los animales. +++Quiere salir unos días de casa porque su hermano Juan "...me hace la vida imposible, me quita la comida..." +++SE le plantea la posibilidad de irse a un centro, pero dice que sus animales son su vida. No obatante, NO parece haber rechazado esta posibilidad de una forma radical. +++ULTIMO INYECTABLE: HACE UN MES +++PRÓXIMO INYECTABLE: ABRIL. +++Llamo a los dos teléfonos que me da de su hermana: en uno salta el contestador, en el otro cortan sin cogerlo y no lo cogen en llamadas sucesivas.Otro teléfono que me ha dado Eugenia (T.Soc. SSB), el 678-250175, NO ES DE LA HERMANA. +++Llamo al teléfono de Juan que me da Ramón(615-784228) y tampoco lo cogen. +++SOSPECHA: Ramón solamente quería el dinero que se le ha autorizado (30€) porque decía que no tenía dinero para volver.LO de Valencia podría ser una excusa para conseguirlo. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Eugenia (SSB de Jerez de los Caballeros). +++NO cree que sea una buena idea lo del viaje a Valencia y no sabe si su hermana estará de acuerdo con ello. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Mariola, T. Soc. del ESM (41610). +++Opina lo mismo sobre el posible viaje. +++Nos han enviado la documentación para solicitar Dependencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ARTURO'and edp.apellido1='ROCHA'and apellido2='MERCHAN'),'2018-02-14','- AMALIA: REGISTRO Y ENTREGO ACEPTACION PIA PARA RESIDENCIA DE MAYORES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2018-02-14','-AMALIA: REGISTRO Y ENTREGO SOLICITUD DE REVISION PIA Y GRADO PARA TRASLADARLA A PLAZA RESIDENCIAL DE MAYORES .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2018-02-14','(Pedro)Visita de Carmen a la Comisión. +++Quiere ir a ver su casa en Valdecaballeros este mes. +++Hablo con Toni (Futuex): se pondrán de acuerdo con ella para llevarla esta semana o la que viene. +++NOVEDAD: Carmen comenta que, su hija (la de Madrid)se está separando de su pareja y quiere venirse a vivir con ella: "...me ha dicho que de aquí a unos meses- muy contenta con esta posibilidad-". +++Se le plantea la posibilidad de ir pensando en una Residencia pero dice: "...Yo estoy muy bien ahora, dímelo cunado tenga 82 años...-dice con una sonrisa "traviesa"-"','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA MERCEDES'and edp.apellido1='PEREZ'and apellido2='PINNA'),'2018-02-14','-AMALIA: ME REUNO EN EL SEPAD ( BADAJOZ ) CON JORGE MUÑOZ TINOCO, JEFE DE SECCIÓN DE CENTROS. HACE MESES QUE ESTÁ ATENDIENDO A MERCEDES QUE SOLICITA PODER ENTREVISTARSE CON LA CTAEX. ME INFORMA SOBRE ESAS VISITAS Y LE PIDO QUE LA PROXIMA VEZ QUE VAYA LA DERIVE A LA GERENCIA DE LA CONSEJERIA PARA QUE YO PUEDA ATENDERLA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CABEZON TERESA'and edp.apellido1='PLASENCIA'and apellido2='MAJADAS'),'2018-01-10','FALLECIMIENTO El 10/01/2018.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2018-02-14','(Pedro)Llamada telefónica realizada a Francisco (666-750146) , a petcición suya a través de Encarnación, T. Social del C. Salud. +++MOTIVO:el "bajón" que ha tenido después de las Navidades. "Mi pareja me dijo que no quería saber nada con enfermos mentales...La ropa que me regaló no la quiso pagar y ahora tengo yo que pagar la factura...Me siento muy solo y solo tengo a ella..." +++"Rosa, mi Psiquiatra, me ha adelantado la cita a esta mañana y le he dicho que había abusado de la Etamina (medicación) y me ha dicho que por eso había tenido este bajón. Me ha dado cita para dentro de tres semanas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ROSA'and edp.apellido1='DELGADO'and apellido2='ROMERO'),'2018-02-10','EXITUS El 10/02/2018. Comunica su fallecimiento Dña. Julia Moreno, TS de Rosalba.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2018-02-14','(Pedro) Visita no programada a la Comisión. +++Ahora Consuelo NO QUIERE IRSE al CRR de Cáceres: "...no sé por qué pensaba a sí, pero me he dado cuenta de que aquí estoy mejor...-¿por qué has cambiado de forma de pensar?-...en parte porque estoy muy bien con José Manuel y en parte porque allí hay muchas más actividades y más control. Aquí puedo salir más a la calle y eso..." +++"la Psicóloga del CRR de Cáceres, me dijo que este viernes la llamara por teléfono para decirle definitivamente si me quería trasladar o no ...Así que el viernes la llamaré y le diré que ya no me quiero marchar". +++Le informo de que no se puede activar un trámite y luego renunciar sin más a lo solicitado, por lo que no se le puede asegurar que esto no siga adelante.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2018-02-14','-AMALIA : NOS INFORMAN DE LA NUEVA DIRECCION DE SU ABUELA. Residencia Coordinación-coordinacion.re@aprosuba3.org>; Os comunico la nueva dirección de la abuela de Dani, donde suele pasar los fines de semana. Corte de Peleas, nº 2 1ºC 06008 Badajoz (San Roque)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2018-02-14','-TF DE LA ABUELA ( 619085037) EMILIA. -AMALIA: QUEDO PARA HACER VISITA AL DOMICILIO DE LA ABUELA CON CATI ( AP. 3 ) . AHORA CONVIVE LOS FINES DE SEMANA CON SU MADRE Y LA PAREJA DE ESTA. HUBO ORDEN DE ALEJAMIENTO DE SU MADRE POR INCESTO .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2018-02-15','(Pedro)Conversación con Julián. +++A las 13h informarán sobre el resultado de la ecografía que se le ha realizado a Tomás. Si el resultado es positivo, tiene prevista el alta para hoy (de hecho ya le están preparando la habitación por si se confirma). +++Está mejor de ánimos, sigue con heridas en la boca debido a la intubación que sufrió y la orina está volviendo a la normalidad.','1');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2018-02-15','a','1');
