insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA DOLORES'and edp.apellido1='FERNANDEZ'and apellido2='BAEZ'),'2018-02-15','(Pedro)Visita de Antonio y Mariloli a la Comisión (con cita). +++Quieren hacerse pareja de hecho e ir a vivir a Almendralejo. +++Antonio quiere ir a ver su casa de Talavera la Real.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='RIVERA'and apellido2='RAMOS'),'2018-02-15','(Pedro) Se presenta en la Comisión D. Joaquín Rivera Ramos 671160838/644762329 hija ??), hermano de D. José. +++FINALIDAD: que su hermano le preste más de 3600 € de una deuda que contrajo con Cetelem y cuyo pago vence hoy, día 15. Al parecer, su hermano le dijo que le daría el dinero (como en otra ocasión ¿?). Se le explica que el dinero de su hermano es para sus gastos: "...Pero si tiene más de 7000€ -dice- para qué lo va a necesitar él..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DANIEL'and edp.apellido1='MONTAÑO'and apellido2='RANGEL'),'2017-08-15','-AMALIA: REALIZO VISITA DOMCILIARIA CON CATI DE APROSUBA 3 . LA VIVIENDA ESTÁ EN SAN ROQUE , UNA VIVIENDA VIEJA CON HUMEDADES , SIN LUZ ( SE LA ESTABAN INSTALANDO ) Y CON AGUA DEFICITARIA . TIENE 3 DORMITORIOS , UNO ES DE LA ABUELA , OTRO CON MOBILIARIO NUEVO ES PARA DANI Y EL DE MATRIMONIO QUE DICE LO TIENE LIBRE. HEMOS VISTO ZAPATILLAS DE HOMBRE EN LA CASA , CREEMOS QUE SU HIJA PILI Y LA PAREJA DE ÉSTA CONVIVEN EN ESA CASA AUNQUE ELLA LO NIEGA. NOS CUENTA UNA HISTORIA ROCANBOLEESCA DEL POR QUÉ HA DEJADO SU CASA , EL EX MARIDO LE HA DADA 6,5 MILLONES DE PESETAS Y LE HAN DADO DIAS PARA SALIR DE ALLÍ . NO HA PODIDO COGER NADA DEL MOBILIARIO O ENSERES DE LA CASA. DICE PAGAR 300€ DE ALGUILAR Y PERCIBE PNC JUBILIACIÓN. NO CUADRAN LAS CUENTAS , AUNQUE DICE IRÁ TIRANDO DEL DINERO QUE LE HA DADO SU MARIDO. DESTACA UNA TV NUEVA DE PLASMA DE TAMAÑO CONSIDERABLE QUE HA COMPRADO , ASÍ COMO UN SOFÁ , UNA MESA Y EL CUERTO DE DANI . CONTACTARÉ CON LUIS BOTE ( TS DE LA ZONA ) PARA OBTENER MÁS INFORMACIÓN , ELLA YA LO HA VISITADO . FIRMAMOS LAS TRES PERSONAS PRESENTES EN LA VISITA UNA SERIE DE CONDICIONES , ENTRE ELLAS QUE LA ABUELA GARANTIZARÁ LA PROTECCIÓN DEL CHICO Y LA NO CONVIVENCIA DURANTE LOS FS DE LA MADRE DE DANI EN ESE DOMICILIO . EN COORDINACION CON CATI VAMOS A SEGUIR AUTORIZANDO LAS SALIDAS LOS FS , DANI LAS RECLAMA MUCHO PERO SEGUIREMOS ANALIZANDO LA SITUACIÓN. SERÁ CONVENIENTE REALIZAR OTRA VISITA EN LA QUE ESTÉ PRESENTA LA MADRE DE DANI MÁS ADELANTE, CUANDO ESTÉN MÁS RELAJADOS .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2018-02-16','Iciar: Llama Mariola de Salud Mental 41610- por el tema del pitbul que Ramón mantiene en su casa. Al ser una raza potencialmente peligrosa RAmón debería de tener una autorización para poder ser dueño de esa clase de perro. Según Mariola o bien se pide esa autorización que conlleva una serie de examenes médicos o bien se le comunica al ayto. para que vaya la policía al domicilio de ramón, algo que por otra parte sería más traumático.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2018-02-16','-HABLO CON JOSE MIGUEL DEL MANZANO ( 64597) PARA COMUNICARLE QUE EN UNOS DIAS DEJAREMOS LA PLAZA . LE ENTREGARÉ EL OFICIO ORIGINAL EN PERSONA','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERRERA'and apellido2='CAMBERO'),'2018-02-16','-AMALIA : ESTOY PENDIENTE DE RECIBIR EL I. MEDICO PEDIDO A LA TS DE ALBALA PRA TRAMITAR L. DEPENDENCIA. HAY QUE RENOVARLE PREVIAMENTE EL DNI PTE . DE QUE ME DIGA LA TS CÓMO VAMOS A PROCEDER. EL DIA 23 MARZO TIENE CONSULTA MEDICA, LES PIDO QUE DESDE EL CENTRO CONTACTEN CON TAXI Y CUIDADORA Y NOS PASEN LA FACTURA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2018-02-16','-AMALIA : ENVIO OFICIO AL C.EE LOS ANGELES PARA CAMBIO DE EXPEDIENTE. HOY ME REUNO CON LA ASOCIACION PARA COMENTARLE AL CHICO EL CAMBIO DE DOMICILIO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='RIVERA'and apellido2='RAMOS'),'2018-02-16','(Pedro). Acude su hermano, D. Joaquín, nuevamente a la Comsiión demanadando el dinero de su hermano para pagar la deuda que D. Joaquín tiene con cetelem. +++Se le insiste en que no se va a prestar ese dinero porque es de D. josé y es para cubrir sus necesaidades, presentes y futuras. +++Dice que ha hablado con su hermano y que se ha enfadado mucho porque dice que él con su dienreo pude hacer lo que le dé la gana. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Intento hablar con el CSS de Mérida pero no lo consigo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VICTORIA'and edp.apellido1='MARQUEZ'and apellido2='ANDRADE'),'2018-02-16','Correo-e de Pilar, T. Soc.del CSS de Mérida: La paciente Victoria Márquez Andrades ha causado Alta en la UDAC con fecha 15 de febrero de 2018; este mismo día ingresa en el centro"La Providencia" en la localidad de Ribera del Fresno (Badajoz). Se enviará a esa CT factura de los gastos de transporte en taxis.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='CACHO'and apellido2='GARCIA'),'2018-02-16','(Pedro) Llamada de Inma, T. Soc. del Centro "Padre Cristóbal" de Mérida. +++Rafael va al centro de forma esporádica. El lunes va a volver. Ha solictado a la compañera que le tramite alguna pensión. +++Comento con Inma que debería pasar por Cadex (se negó en su día) y valorar dependencia. +++El lunes va a volver a ir y nos llamará si, como le digo, quiere acercarse a la Comisión. +++SIGUE CON CONSUMO ACTIVO y SIN DESEO DE DESINTOXICARSE, dado que ya lo ha intentado convencer Inma.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2018-02-16','(Pedro)Mariví: +++Ya tiene Grado II. Solicitarán cambio de PIA para centro de persoinas con discapacidad. +++Se le envía nuevamente DNI de Consolación y Margarita, ambos compulsados.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='DELGADO'and apellido2='MOTIÑO'),'2018-02-16','-AMALIA : REALIZO VISITA DOMICILIARIA A EALEX , ASOCIACION ESCUEALA ANIMACION LIBRE EN CIUDAD JARDIN , DONDE SE ENCUENTR CRISTOFER MONTERO. ALLÍ RESIDE INMACULADA GOMEZ DELGADO , ( 634887653) HIJA DE NUESTRA TUTELADA. TIENE 24 AÑOS Y ESTÁ EN ESE PISO Y ESTUDIA EN LA UNIVERSIDAD. LOS FINES DE SEMANA SE VA A AZUAGA Y CONVIVE EN EL CORTIJO CON SU MADRE. LA SITUACIÓN DE SU MADRE DICE QUE HA MEJORADO DESDE QUE SIGUE LA MEDICACION , SE PONE INYECTABLE UNA VEZ AL MES AL QUE LA ACOMPAÑA LA MADRE DE SU NOVIO Y TOMA DOS PASTILLAS POR LA NOCHE QUE SE ENCARGA SU NOVIO DE IR A LLEVARSELAS TODAS LAS NOCHES. YA TIEEN LUZ , PERO LA DEUDA DE 1000€ SIGUE PENDIENTE CON ENDESA . EL CONTRATO ANTERIOR ESTABA A NOMBRE DEL PADRE ( FALLECIDO HACE 11 AÑOS ) Y CTAEX HA GESTIONADO UNO NUEVO A NOMBRE DE LA MADRE. LE SIGUEN MANDANDO CARTAS Y DICE QUE HAY UN PROCEDIMIENTO JUDICIAL ABIERTO EN CONTRA DE SU MADRE Y QUE ESTA DOCUMENTACIÓN SE LA HA DADO A LA DELEGADA TUTELAR ( SILVIA ) . LE RECLAMANT TB UNA DEUDA CON CANAL + , LO TUVIERON HACE MUCHOS AÑOS Y POCO TIEMPO . DESEINSTALARON EL TERMINAL PERO NADIE LE DIÓ DE BAJA . LA DEUDA ASCIENDE A 500€ . CONCEPCION NECESITA UNA DENTURA POSTIZA , LE HAN DIAGNOSTICADO UN TUMOR Y SI NO SE LA PONE CORRE EL RIESGO DE QUE ESTE SE MALIGNIFIQUE. EL PTO. ES DE 7000€ ( SE LO DIO A FUTUEX ) Y SE PODRIA FINANCIAR , TIENE ALGO AHORRADO ?? NO SABEMOS SI ESTÁ VALORADA POR DEPENDENCIA . AVERIGUAR Y TRAMITAR EN SU CASO . TRAMITAR BONO SOCIAL PARA LA LUZ . NECESITAN UN MOTOR PARA EL AGUA , CUESTA 250€ , TIENE CAPACIDAD ECONOMICA ? VER AYUDAS PARA MOBILIARIO , POR SI PUEDE MEJORARSE ALGO . LA MADRE DE CONCE DE 89 AÑOS ESTÁ INGRESADA EN R. MAYORES DE LAS HNAS. DE LA CARIDA EN ZALAMEA , JUNTO A OTRA DE SUS HIJAS QUE PADECE DISCAP. INTELECTUAL . INMACULADA ES LA TUTORA DE AMBAS Y ESTÁ MUY AGOBIADA CON ESTE TEMA . NO SABE CÓMO GESTIONAR LA TUTELA , QUIERE DEJAR EL CARGO . TIENENE 4 VIVVIENDAS EN ZALAMEA PERO NO SABE CÓMO VENDERLAS . TB TERRENO AGRICOLA DEL QUE PAGA IMPUESTOS PERO EXPLOTA UN VECINO QUE NO LE DA NADA A CAMBIO . TIENE QUE HACER DECLARACION ANUAL ?? ESTA NIÑA NO TIENE CAPACIDAD PARA EJERCER ESTE CARGO EN SU SITUACIÓN , TUTELADA POR LA JUNTA . O SOLICITAMOS LA REMOCION DEL CARGO O LA AYUDAMOS A REALIZAR LA TUTELA . SE PASARÁ OTRA SEMANA CON TODA LA DOCUMENTACIÓN QUE TIENE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CRISTOFER'and edp.apellido1='MONTERO'and apellido2='VAZQUEZ'),'2018-02-16','-DESPUES DE LA VISITA DOMICILIARIA EN EALEX , SE QUEDA TRANQUILO. CONTACTO CON SUS TIAS RAFELA ( BADAJOZ ) 637808916 Y BELEN ( MONTIJO ) 670958395 PARA COMUNICARLES EL TRASLADO . SU TIA LA DE MONTIJO SE MUESTRA CONTENTA Y NOS PIDE AUTORIZACION PARA LLEVARSELO EN S.SANTA. YA LE HE EXPLICADO EL PROTOCOLO PARA LAS SALIDAS. SE LO COMUNICARÁ A SU HNA. CRISTINA . EALEX SE PONDRÁ EN CONTACTO CON V.T. PARA HACER EL TRASLADO CUANDO EL CENTRO NOS AVISE DE SU TRASLADO DE EXPETE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2018-02-19','Iciar. Como nos solicta Longina, T.S. de Madrigalejo, solicitamos por correo postal con a.r. a CAISS de Cáceres el certificado de la perstavión por hijo a cargo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE'and edp.apellido1='CAYERO'and apellido2='AGUILAR'),'2018-02-19','(Pedro)Converación con Maribel, Plena inclusión Vva. de la Serena (924-840900). +++La cita del 22 de marzo es solamente para consulta, por lo que la decisión de hacerle el estudio, debiendo permanecer en el hospital durante el mismo, se tomará posteriormente. +++TRASLADO. Maribel considera que debe ir acompañado por dos personas del Centro: la Enfermera y el Educador. Pero considera que ambos se deben ocupar de él durante el traslado, por lo que sería precisa una tercera persona para conducir. PROPUESTA:Cruz Roja. Consultarán precio y nos lo dirán.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2018-01-23','Iciar: Hablamos con el Juzgado de Villanueva nos confirman que a la comparecencia por el tema de abusos no hace falta que vaya la Comisión ni tampoco Yolanda. Llamo a Aprosuba 9 para informarles. Maribel nos dice que Yolanda recibió el alta el viernes del Hospital y ha salido más desajustada que ingresó. Han enviado la solicitud ala UDAC de Plasencia pero se temen no van a aceptarla pues debido a falta de perfiles profesionales, psicólogos y terapeutas, no están admitiendo a ningún nuevo paciente. Quedamos en hablar sobre cómo termina el tema del juicio por abusos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2005-04-21','Se tiene solicitado(abril 2004) acudir a Proines de Don Benito a fin de prepararla para posible ingreso en Piso Tutelado. Pendiente de ingresar en la Unidad de Media Estancia del Hospital Psiquiatrico para pasar después a los Pisos Tutelados. Ingresa por vía de urgencia en el CAMP de Don Benito. Discapacidad del 65%. Oligofrenia, retraso mental, epilepsia. La pensión (PNC) de Agosto se la han ingresado ya en la cuenta nueva de Caja Extremadura en Don Benito (nº2099.0046.76.0070015980).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2018-02-19','Correo-e de carmen Ferrer. +++Equipo de Salud Mental de Mérida que atiende al usuario de CRR *Jose Manuel Romero Mediavilla*, le han adelantado la cita para el dia 22 de febrero a las 11:00h con Almudena que es la enfermera y a las 11:20h con su psiquiatra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='YOLANDA'and edp.apellido1='CALDERA'and apellido2='MARTIN'),'2018-02-19','(Pedro)Conversación con Maribel, Directora de Plena Inclsuión Vva. de la Serena. +++Se informa del Juicio:se condenó al pago de una indemnización al agresor, que el letrado de la abogacía de la Junta propuso, sin que ello se hiciera constar en la sentencia, que podría destinarse a algún tipo de terapia que puediera ayudar a Yolanda a corregir, en la medida de lo posible, tanto su comportamineto genral como el que presenta en la esfera sexual. +++Lo tendrán en cuenta por si concen alguna terapia externa que sea aplicable en este caso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2018-02-19','Correo-e de Julián del día 16 de febrero: +++Te informo que Tomás ha recibido el alta y ha llegado a COCEMFE a las 14.00h Seguirá con antibiótico durante 15 días y posteriormente se le realizará un urocultivo para analizar si ha remitido totalmente infección.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2005-04-21','Se recibe Informe de la Trabajadora Social de Badajoz y se solicita cita en el CADEX para revisión con vista a solicitar al Juzgado revisión de la Sentencia de Incapacidad y autorización para ingreso en Centro. Reside en Badajoz. Tiene varios hermanos, pero sólo se ocupa de és Geni. Las necesidades de alimentación y vestuario las tiene cubiertas. Compra en un establecimiento determinado y nosotros pagamos por transferencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIANO'and edp.apellido1='RODRIGUEZ'and apellido2='DE LA CONCEPCION'),'2018-02-07','EXITUS El 18/05/2017. Informa del mismo el Jzdo. nº. 4, de Badajoz. Es quién conocía del caso de incapacitación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FRANCISCO'and edp.apellido1='AYALA'and apellido2='NUÑEZ'),'2018-02-19','(Pedro) Conversación con Francisco. +++Pendiente de intervención ocular. Posiblemente será para marzo cuando le llamen para el preoperatorio. +++También problemas con el brazo, pero ya le han dicho que no se puede hacer nada más, según varios especialistas, tras siete intervenciones practicadas.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2018-02-19','(Pedro)Conversación con el Dr. Marcelino Pacheco, del C.Salud de Oilvenza.Correo-e:marcelino.pacheco@salud-juntaex.es +++Se solicita Informe Médico en modelo Anexo II para solicitar acceso a Centro de Discapacidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='RODRIGUEZ'and apellido2='CALERO'),'2018-02-09','REINTEGRO CAPACIDAD Por Sentencia nº. 547/17, de 21 de noviembre, se deja sin E/ la incapacidad de D. Juan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-02-19','Llega la Resolución de la D.G. de Infancia y Familia ratificando la tutela administrativa de Mª del Rocío, hija de Beatriz.En ella se indican, entre otros aspectos, los siguientes: +++RÉGIMEN DE VISITAS: ++++++++Dª Beatriz: no se establece ninguno en tanto se reciba Informe del Centro Plena Inclusión de Llerena sobre la conveniencia o no de dichas visitas y la Com,isión tome decisión en base a ello. ++++++++ D. Antonio y Dª Magdalena (padre y abuela paterna respectivamente): 1día/mes en Punto de Encuentro Familiar de D. Benito. +++INFLUENCIA del ENTORNO de Beatriz: ++++++++Su madre la llama diciendo que se ha quedado sin su hija y que quiere hacerse cargo de la nieta. ++++++++Antonio y Magdalena: ver incidencias anteriores. +++CONVERSACIÓN con Mª Ángeles, Psicóloga de Plena Inclsión (924-870293): ++++++++La insistencia de Beatriz en ver a la niñaes cada vez mayor, si bien sigue paraticipando y convivinedo muy bien en el Centro. ++++++++POSIBILIDAD DE HABLAR CON ELLA: "...Dijo que sí, que quería hablar contigo pero que por teléfono, porque si venías a verla lo mismo le decías que la ibas a llevar a otro centro...". Volverá a hablar con ella para tratar de que le podamos hacer una visita en el centro a lo largo de esta semana.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAFAEL'and edp.apellido1='DOMINGUEZ'and apellido2='GARCIA'),'2018-02-20','Iciar: Llamo a Dolores para saber si ya tienen el informe médico del centro de salud. Me indica que todavía no lo tienen, va a hablar con la directora del Centro para saber si ya tiene cita con el neurólogo o el médico de familia. Le indico que estamos pendiente del informe.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PEDRO'and edp.apellido1='SUDON'and apellido2='HERNANDEZ'),'2018-02-20','(Amalia y Pedro) Reunión con María Rapado y Tomás Moreno de la Dirección de Caser Olivenza (924-492890. Fax: 924-492535. Correo-e: tmoreno@caseresidencial.es). +++Información general de la situación personal y jurícida de D. Pedro y algunas propuestas de intervención con él en el sentido de darle alguna responsabilidad.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2018-02-20','(Pedro) Llamada de Javier Pecero, Director CRR de Cáceres. +++"D. Juan dice que se marcha del piso...que allí huele a transilium quemado....y que se marcha". +++Propuesta: ir a verlo este viernes para hablar con él y tratar por enésima vez de hacerle comprender que no tiene recursos económicos para plantearse un piso de alquiler. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Javier: +++Han tenido que llevar a Juan a Urgencias: no han considerado necesario el ingreso pero le han advertido que si se va del piso tutelado es cuetión de ytiempo que vuelva a recaer y termine ingresando nuevamente en un centro. +++DESENCADENANTE: los días que ha permanecido en residencia se ha encontrado bien y con buena actitud. Ha sido cuando se le ha llevado al piso (ha pasado una noche) cuando ha empezado a decir queél se quiere ir, que no quiere estar allí, que se va a su pueblo y buscará trabajo. +++++Le propongo a Javier que le plantee la posibilidad de permanecer en residencia (dado que se encontraba bien en ella) para ver si persiste en su actitud y que, en cualquier caso, el jueves o viernes quiero ir a verle, por lo que le pidan que eespere a hablar conmigo (por si sirve de algo).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GONZALEZ'and apellido2='HERNANDEZ'),'2018-02-20','-AMALIA: NOS LLAMA EUGENIA , TS DEL SSB , JUAN FCO. HERMANO DE RAMON QUIERE HABLAR CON NOSOTROS. NOS CUENTA QUE SU HERMANO LO AMENAZA CON UN CUCHILLO, QUE RASTREA POR LOS CONTENEDOES Y SE LLEVA A CASA TV...Y QUE NO SE PUEDE CONVIVIR CON ÉL. LE ANIMO A QUE COMENTE ESTA SITUACION CON EL PSIQUIATRA DE RAMON , POR SI CONSIDERA ALGUNA MEDIDA A TOMAR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2018-02-20','-AMALIA: SOMOS TUTORES DE ESTA SEÑORA . HE PEDIDO A FUTUEX VISITA INCIAL PARA VALORAR INTERNAMIENTO INVOLUNTARIO EN R.MAYORES . SI PROCEDE LA PARTE JURIDICA SOLICITARÁ AL JUZGADO LA AUTORIZACIÓN. YA HE PEDIDO QUE SE LE HAGA SEGURO DE DECESOS . NO ESTÁ VALORADA POR DEPEND. ESTÁ EN TRÁMITE EL PROCESO. NO PERCIBE PENSION, CONVIVE CON DOS HERMANOS QUE SUPERAN EN INGRESOS . SI SALE DEL DOMICILIO SE LE PEDIRÁ .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2018-02-20','Ingresa por Urgencias hoy, 20 de febrero, en la UHB de Mérida y a petición propia. +++La atiende David, Psiquiatra.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS'and edp.apellido1='VAZQUEZ'and apellido2='DIAZ'),'2018-02-21','(Pedro)Llamada de Paula, atención discpacidad intelectual en prisiones: +++Jesús ha solicitado permiso de salida para pasarlo con su hermana al tener derecho a él por haber cumplido 3/4 partes de la condena, pero no se le ha concedido por tener sanciones. llegado el caso, y cumpliendo con su derecho a dichos permisos, se comunicaría previamente a la Comisión anted de autorizarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-02-21','(Pedro) Visita a Beatriz en Plena Inclusión de Llerena. ******PRIMERA PARTE: reunión con Cristina (Directora), Mª Ángeles (Psiquiatra), Mercedes (T. Social) y Silvia (Delegada Tutelar de Futuex). ******SEGUNDA PARTE +++Quiere ver a su hija. Es una demanda que se ha incrementado durante las últimas tres semanas, también quizá por la interferencia de su entorno (Antoni, Magdalena, vecina, etc.). +++++Se considera que en estos momentos es necesario facilitar dicho contacto, por lo que desde el centro remitirán a la Comisión Informe en dicho sentido, quedando la continuidad de dichas visitas supeditada al efecto beneficioso que las mismas supongan para Beatriz. +++++SE le trata de explicar que serán visitas, pero que no significará que se pueda quedar con ella para cuidarla: se le explican las múltiples necsidades de un bebé de cuatro meses y la dificultad de beatriz para atenderlas las 24 h del día. +++Quiere ir a Trujillo para ver a sus animales (se le propone al centro posible colaboración con la perrera municipal a efectos de voluntariado) y para la fiesta de Chimiri y del Queso -"...porque he ido todos los años..."- (se le plantea al Centro la posibilidad de organizar para esas fechas alguna excursión conjunta del centro). +++Pregunta si puede tener otra madre, porque la suya le dijo que la había perdido. +++Beatriz consiente en pasarnos los mensajes y audios de wasapp recibidos de su entorno personal.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-02-22','(Pedro) Conversación con Mara (DG Infancia y familia). +++Informar sobre la situación de Beatriz en relación al establecimiento de régimen de visitas a su hija.Estamos a la espera de recibir el Informe de Plena Inclusión sobre la conveninecia de las mismas. +++RÉGIMEN DE VISITAS: Punto de Encuentro de D. Benito (Centro de Día de Mayores "San isidro". +++++HORARIOS: Miércoles (11-13h), Viernes (18:15-20:15), Sábados y Domingos (17:15 a 20:15h). +++++Una vez vista la conveniencia de dichas visitas (ayer se habló con Bestriz sobre ello) se plantea a Mara que para Beatriz sean MIÉRCOLES O VIERNES Y SIN QUE COIINCIDAN CON LAS DEL PADRE (para faciliatr traslado de Betariz en jornada laboral). +++Mensajes y audios de wasapp que nos dió ayer Bestriz (enviarlos a Curro para considerar su conveniencia de prenestar en juicio). +++El juicio (comparecencia?) del día 7 de febrero se ha aplazado sin señalar nueva fecha (al menos que sepamos). +++SALUD DE ROCÍO: Cruz Roja hace el seguimineto de los acogiminetos externos, y en estos momentos se ha detectado ciertos problemas de mobilidad en sus piernas. Está acudiendo al Hospital para Rehabilitación y también acude a Habilitación Funcvional. Ni Beatriz ni la familia del padre ni él mismo saben nada sobre ello. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Se recibe por correo-e el Informe mencionado sobre la conveninecia de iniciar el régimen de vistas con su hija.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MARIA'and edp.apellido1='MORON'and apellido2='HERNANDEZ'),'2018-02-22','CADEX Se recibe Resolución y DTF. Le conceden un 69%. Presenta: 1.- retraso mental ligero; 2.- pérdida de agudeza visual binocular leve; 3.- alteración de la conducta; 4.- retraso mental ligero. Se remite copia y tarjeta acreditativa al centro (Asoc. Vera) para que figure en su expte.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BLAS'and edp.apellido1='GUERRERO'and apellido2='ASEGURADO'),'2018-08-22','CADEX Se recibe Resolución y DTF. Le reconocen un 65%. Según el DTF padece: 1.- retraso mental ligero. Se remite copia y tarjeta acreditativa al centro (R. Juan Carlos Rdguez. Ibarra) para que lo archiven en su expediente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2018-02-22','(Pedro)Conveersación con Julián, Gerernte de Cocemfe Cáceres. +++El pasado sábado acudió al Hospital San Pedro DE Alcántara porque tuvo un pequeño desprendimiento de la sonda, volviendo con normalidad al centro. +++Se le envía la autorización para las salidas de Tomás con Nace.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2018-02-22','(Pedro)Conversación con Margarita: +++"Estoy muy contenta aquí y me quiero quedar en este centro.No me vas a llevar a otro, verdad...?" +++Ha empezado los talleres de ALFOMBRAS, COCINA Y MAQUILLAJE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2018-02-22','(Pedro)Llamada de Mariví (T. Soc. CSS Plasencia: +++Han llamado del SSB de Guadalupe diciendo que Juan se encuenytra en los Servicios Sociales. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro) Conversación con Javier, Director CRR de Mérida: +++"Ayer dijo que se marchaba, que no agunataba más y que no iba a esperar a que tú hablaras con él. Intenté que me dijera cómo pensaba utilizar el dinero que llevaba y la manera de poder contactar con él. Me dijo que llamara al SSB y le propuse que se acercara por allí cada dos días para saber de él..." +++"Firmó el alta voluntaria, pero le fije que lo hiciera con fecha de 28 de febrero, con la esperanza de que recapacitase y volviese al Centro sin haber perdido la plaza..." +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Conversación con SSB. +++Raquel, la Trabajadora Social no está. Volveré a llamar.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONSUELO'and edp.apellido1='NEVADO'and apellido2='PACHECO'),'2018-02-22','(Pedro)Conversación con Javier Pecero (CRR Mérida). +++Consuelo fue trasladada el lunes 19 de febrero al CRR de Cáceres. Fue por traslado y no por permuta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2018-02-22','ICIAR, llama Ana Royo. Comenta que Antonia fue hace unos dás a la casa de los padres en su pueblo con la nieta de la manuela, a señora donde vive. A preguntas de Ana sobre el motivo de la visita le dijo que había ido "a buscar unas escrituras de un terreno porque se las están procurando", a lo cual Ana le dijo que si iba a hacer lo mismo que con el terreno anterior, y Antonia le dijo que este terreno valía más. Ana le insistio en que no podía vender nada pues el terreno era de los 3 hermanos. Además en la visita se llevó herramientas del hermano, enseres... Han comprobado que herramientas de la misma clase se están vendiendo por internet.La prima dice que este mes Antonia no le ha pagado los 500€, Antonia le ha dicho que los ha perdido. Supuestamente Antonia tendría una boda en septiembre para lo cual "necesitaría" comprarse un vestido. TAnto Ana como Silvia no consideran que ahora se le debiera dar dinero para dicha compra. Ana pregunta por la posibilidad de ampliar la incapacitación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2018-02-22','(Pedro) Conversaación con Mª Antonia, Psiquiatra de la UHB de Mérida. +++ALTA de Concepción en el día de HOY. En la UHB se encuentra estable, se le ha ajustado la medicación y quiere además volver al CRR.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2018-02-22','(Pedro)Llamada de Alberto, Valorador Dependencia (Equipo de BRozas) (21841 y 927-270466). +++Han tratado de visitar a Dª Luisa pero no les ha abierto la puerta. +++Pendiente de visita de Futuex (posibilidad de ir con Dependencia). +++VOLVER A LLAMAR A Alberto.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2018-02-23','(Pedro)Visita de Manuel Contador: +++Ha estado mirando pisos de alquiler, amueblados, en Badajoz.Ha tyraído tres teléfonos (cree que son de inmobiliarias): +++++Juan José Macías (649-894500). Piso en calle Felipe Checa+++++Sheila(691-717598) Piso en calle Juan Leandro Jiménez, 3ª planta (San Roque)+++++Ángel (692-641290). Piso en calle Augusto Sánchez. +++SE le vuelve a proponer que busque el piso en Mérida, por la proximidad de los recursos que han estado atendiéndole desde que ingresó en el CSS. Pero el no quiere Mérida: "...Yo quiero vivir en Badajoz, porque he nacido allí, mi familia está allí..." +++Hablo con Toni, Futuex, para acompañarlo a ver los pisos: le doy los teléfonos para que se pongan de acuerdo en la fecha para visitarlos. Me avisarán del sía para comunicarlo a Asun.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-02-23','(Pedro)Conversación con María, T. Soc.C. Salud de Zafra: +++No ha vuelto a ir por allí. +++Me enviará próxima consulta para tratamiento y poder localizarlo cuando esté allí. +++Idelfonso no acudió el día 8 de febrero a la cita con el Psiquiatra. El 27 de febrero tiene cita con enfermería.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA PILAR'and edp.apellido1='GARCIA'and apellido2='MORENO'),'2018-02-23','(Pedro) Llamada de Soledad, T. Soc. H. Virgen de la Montaña (56950): +++Dª Pilar ingresó el pasado día 9 de febrero en la UHB por intento autolítico.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GERMAN JOSE'and edp.apellido1='MONTERO'and apellido2='MORENO'),'2018-02-23','En relacion con el PDA 501/2017, seguido en el Juzgado de Primera instancia e Instrucción nº 3, de Plasencia, por un presunto delito de agresiones sexuales contra su padre, acudimos al Juzgado nº 3 de Mérida, en ofrecimiento de acciones.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ADRIAN'and edp.apellido1='ORTIGOSA'and apellido2='FUENTES'),'2018-02-26','(Pedro) Llamada al C. Salud de Villanueva del Fresno: +++Tenía llmada perdida del viernes 23 de febrero a las 19:24h desde la extensión 71314. Comentan que sería del PAC pero que no le consta aviso alguno. Lo consultará y volverá a llamar. +++La Trabajadora Social del C. Salud tiene el siguiente horario: miércoles y jueves en Villanueva del Fresno; lunes en Torres de D. Miguel (927-441377)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GENARO'and edp.apellido1='RUIZ'and apellido2='GARCIA'),'2018-02-08','(Pedro)Conveersacaión con Loli, T. Soc (la fecha es aproximada). +++Genaro no tiene cita prevista ni en oncología ni en radio ni quimioterapia.PENDIENTE DE CITA EN ANATOMÍA PATOLÓGICA. +++AECC:924-236104. +++AOEx:924-207713.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RUBEN DIEGO'and edp.apellido1='BAUTISTA'and apellido2='GOMEZ'),'2018-02-08','(Pedro)Conveersacaión con Loli, T. Soc (la fecha es aproximada). +++Rubén no tiene cita prevista ni en oncología ni en radio ni quimioterapia.PENDIENTE DE CITA para tac. +++AECC:924-236104. +++AOEx:924-207713.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='GONZALEZ'and apellido2='VICENTE'),'2018-02-26','-AMALIA: LLAMO AL SSB DE MIJADAS Y HABLO CON ANABEL . HACE MUCHO TIEMPO QUE NO SABE NADA DE ÉL NI DE SU MADRE. NO HAN PASAO POR EL SSB .NO PUEDE FALICITA MÁS INFORMACIÓN. -LA DECLARACION ANUAL DEL 2016 RECOGE CORRECTAMENTE QUE ESTE CHICO PASA DE PISO SUPERVISADO ( POR ALTA VOLUNTARIA ) AL DOMICILIO CON LA MADRE. EN LA DECLARACIÓN ANUAL DEL 2017 SE HA PRESENTADO UN I.SOCIAL DEL SSB DE MERIDA QUE CREEMOS QUE ESTÁ EQUIVOCADO , INDICA QUE SIGUE VIVIENDO EN PISOS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CIPRIANO'and edp.apellido1='MIGUEL'and apellido2='BAZAGA'),'2018-02-26','En relación con las DPA 764/2016, seguido en el Juzgado de Primera Instancia e Instrucción nº 1, de Plasencia, en el que aparece como denunciante, contra Antonio Romero Romero, por un delito de lesiones, ponemos en conocimiento del Juzgado el domicilio, a efectos de notificaciones. En este procedimiento, una vez se decrete la apertura de juicio oral, nos notificarán, para que actuemos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='RUIZ'and apellido2='LARENA'),'2018-02-26','(Pedro)Visita de Carmen a la Comisión. La tendemos Alberto y yo: +++Ya ha ido a ver la casa. +++Quiere levantar la parte de atrás. +++Cree tener más dinero del que realmente tiene. +++Se le plantea la posibilidad de residencia, pero dice que cuando sea una "anciana".','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GUADALUPE'and edp.apellido1='BARRAGAN'and apellido2='GARCIA'),'2018-02-26','-AMALIA: HE PEDICO A CAROLINA DEL CRR INFORMES MEDICOS ACTUALIZADOS PARA PEDIR REVISION GRADO Y PIA.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='ESTEBAN'and apellido2='IGLESIAS'),'2018-02-26','(Pedro)LLamada de Manuel Zambrano. José Mª se ha puesto en contacto con él para que le mandemos la autorización para que Tomás pueda ir a comer a su casa. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con JUlián: +++Tomás ha pasado bien el fin de semana pero le dijeron que hoy iría a comer con ellos y, al no tener la autorización, no va a poder ser: no ha queriod bajar a comer, aunque lo ha hecho mientras manteníamos esta conversación. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Correo electrónico enviado a NACE: pido que nos envíen el modelo de autorización que ellos consideran adecuado para estas circuenstancias. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Todo ello lo reenvío a Soraya.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='LUISA'and edp.apellido1='REY'and apellido2='CAMPON'),'2018-02-27','(Pedro)Conversación con Toni (Futuex) y Alberto (Dependencia Brozas). +++Virginia va a visitarla hoy. Una vez la conozczn, concertarán nueva visita para ir con Alberto y hacer la valoración de Dependencia. +++Ya he puesto en contacto a Futuex y Dependencia para dicha coordinación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JESUS MANUEL'and edp.apellido1='RAMOS'and apellido2='BARGON'),'2018-02-27','Correo-e de Futuex: Respecto de Jesús, pues tenemos un problema, ahora acabo de hablar con Virginia, que dada la situación se puso en contacto con el casero y también con Jesús, el casero está allí en el piso con la compañera y una vecina que dice que está pensando poner una denuncia... hacen muchisimo ruido, a partir de las 00.00 entra gente con mal aspecto, fuertes olores, etc.. Jesús ha llegado con un compañero que creemos vive alli también, con bastante malos modos, gritando y cantando y se ha vuelto a ir, porque dice que no habla si no es en presencia de la policia... evidentemente nadie quiere llamar a la policia. Lo que vamos a intentar que el casero nos haga el favor, de aguantar unos dias en el piso, y creo que hay que ir buscando otro piso, o un albergue o pensión para Jesus.. de que presupuesto dispone? porque o cambia mucho la situación o el casero le quiere echar de inmediato. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Toni (Futuex) +++Irán viendo la posibilidad de otra alternativa de vivienda para Jesús, quien al parecer se queiere marchar. Eso sí, siempre con sus exigencias de un piso con al menos tres habitaciones para poder estar con sus hijos (cosa que nunca sucede y cuando los ve es con supervisión de la familia).','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA LUISA'and edp.apellido1='FERNANDEZ'and apellido2='GARCIA'),'2018-02-27','-SE ENTREGA EN LA SECCION DE DISCAPACIDAD AUTORIZACION PARA QUE DESDE EL CENTRO SE SOLICITE REVISION CAMBIO DE PERFIL PARA PASAR DE RAL A RAE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2018-02-27','(Pedro)Conversación con Mariví (T. Soc. CSS Plasencia): +++Existe la posibilidad de que Margarita pudiera ocupar una plaza que queda vacante en el Hogar "San Vicente de Paul", de la Hermanas de la Caridad en Plasencia. +++Consideran que no le conviene a Margarita permanecer más tiempo del necesario en el CSS y consideran que esta alternativa pudiera ser muy positiva para ella. +++No es un centro concertado ni subvencionado y, según Mariví, la plaza supone el 75% de la pensión. +++VENTAJA (previsible): dada la buena relación que Margarita ha establecido en el CSS con sus comapñeras y personal, el hecho de que el recurso al que acceda se encuentre en Plasencia crreo que pude favorecer el mantenimineto de esos lazos afectivos recién creados entre ellas, lo que para Margarita sin duda puede ser beneficioso dada la necesidad afectiva que siempre ha requerido.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MUÑOZ'and apellido2='RUIZ'),'2018-02-27','(Pedro)Conversación con Mercedes (T. Soc.) +++Beatriz está bien, impaciente por poder ver a su hija aunque ello no interfiere en la dinámica habitual del día a día. +++Enviarán el Informe con firma por correo-e y ordinario.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-02-27','(Pedro)Llamada de María, T. Soc. ESM Zafra. +++Ha estado en la consulta pero se ha marchado. +++Dice que lo citéis en la Comisión por carta, que él no tiene inconveniente en ir a M´çerida. Citarlo en el APDO. de CORREOS Nº 105. ZAFRA. 0.6300. (BADAJOZ)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2018-02-27','Correo-e de Beatriz: "Hola buenas tardes estoy mala como saven tengo una enfermedad mental mi relagcion familiar es mala me pongo mala cuando estoy con ellos llamen al crps y qe les expliqen cual es el problema necesito pedirles un fabor muy grande si algo me pasa porfabor no quiero qe avisen a mi familia quiero qe alguien de ustedes se encarge de qe este bien atendida en un hospital si es psiquiatrico o de lo qe sea necesito gel pasta de dientes tabaco y qe alguien me lo traiga sera eso posible porfabor llorando les digo no tengo familia estoy sola gracias espero poder contar con ustedes porqe mi madre dice qe ustedes se laban las manos y qe ellos no van acudir y sola estare y qe me pudra" ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Ramón (Gerente del CRPSde Zafra) y Patricia (Psicóloga CRPS Zafra). +++La semana pasada no tuvo consulta con ella. La tiene mañana, miércoles 28, a las 13:00h. +++Seguramnete este fin de semana se ha marchado a casa de sus padre, en Calera, y ha discutido con ellos y eso ha provocado la situación que describe en su correo. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con Beatriz. +++Efecticvmente se fue a casa de us padres y allí discutió con ellos, sobre todo con el padre: "...me echó de casa y, aunque luego se arrepintió, yo decidí marchrame a Zafra. Siempre están a voces e insultos entre ellos y a mí eso me sienta fatal..." +++"Me decían que vosotros no haciáis nada por mí y que si algún día estuviera en el hospital no os preocupariais por...porque estoy sola..." +++Se le tranquiliza en el sentido de que no está sola, que la Comisión está pendiente de ella, el CRPS, el SAD, Marisa, su Psiquiatra del ESM...y que llegado el caso siempre puede contar con todos estos recursos. Se muestra muy agradceida por la llamdad y se le recuerda la cita de mañana con la Psicóloga del CRPS a las 13:00h. +++Pregunta por la cita del Juzgado para la videoconferencia que se aplazó. SE le indica que será el 19 de abril a las 9:30h."lo apuntaré ahora..." +++" POR SI ACASO: la LLAVE de MI CASA la TIENEN en el CRPS"','2');
