insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIO'and edp.apellido1='VAQUERO'and apellido2='PEREZ'),'2018-03-01','-AMALIA : ME LLAMA LA TS DEL SSB MONTIJO , MAYTE , MUY ENFADADA PQ NO ESTAMOS ACOMPAÑANDO A JULIO A LAS REVISIONES MEDICAS. SE VA A OPERAR Y NO HEMOS ENVIADO EL CONSENTIMIENTO SEGÚN CREE ELLA. LE INFORMO DE QUE NO SE HA RECIBIDO CONSENTIMIENTO ALGUNO Y LO PIDO AL HOSPITAL. LE EXPLICO QUE LA CTAEX NO HACE ACOMPAÑAMIENTOS PERO QUE SI NOS INFORMAN CON TIEMPO Y EN LA MEDIDA DE LO POSIBLE PODRÁ IR FUTUEX. ME DERIVA A LA AUX. SAD QUE ES LA QUE CONTROLA TODAS LAS CITAS Y TODO LO DE ESA CASA . TF JUANI GRACIA 666863893. LA LLAMARÉ PARA QUE HAGA ACOMPÑAMIETNO HOSPITALARIO CUANDO LO OPEREN .','2');
