insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='GONZALEZ'and apellido2='VICENTE'),'2018-02-28','(Pedro)Conversación con DªMaría Vicente (madre de JUan): Manifiesta a esta Comisión que la relación con su hijo ha mejorado mucho desde que está con ella, sobre todo porque finalmente ha dejado de gastarse el dinero en jugar desde que está con ella, acude puntualmente a las consultas de Salud Mental que tiene programadas y realiza correctamente el tratamiento que le tienen instaurado. Reconoce ser consciente de las dudas que en su momento manifestó a esta Comisión en relación a la demanda que ahora presenta, pero que está convencida de que, para su hijo y para ella, es lo mejor que puede hacer, contando además con la ayuda que le proporcionará la Ley de Dependencia mediante el Servicio de Ayuda a Domicilio, que ya tiene aprobada, y los Servicios Sociales de la localidad en caso de requerirlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2018-03-02','(Pedro)Conversación con Raquel, T. Soc. ESM de Trujillo (53334): +++Juan tiene consulta con Enfermería de Salud Mental el 12 de marzo a las 12:00h. +++Se avisa a Futuex (Susana) para acompañamiento.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANA PRISCILA'and edp.apellido1='SAQUERO'and apellido2='SANCHEZ'),'2018-03-02','Iciar: Enviado el Cdo de Pensiones al fax del Ayto de Madrigalejo 927 35 48 56 como indicó la T.S. Longina.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN MANUEL'and edp.apellido1='GONZALEZ'and apellido2='VICENTE'),'2018-03-02','(Pedro)Convesración con la Dra. María Josefa Gómez del Castillo, Psiquiatra de D. Juan en el ESM de Cáceres (53420)(54606): +++Acude a las consultas programadas y sigue correctamente el tratamiento indicado (la última en diciembre de 2017). También en dichas consultas Dª maría había ya manifestado el deseo de hacerse cargo de su hijo y que la relación entre ellos había mejorado considerablemente, gracias entre otros factores a su adherencia al tratamiento y a su adecuado seguimiento desde Salud Mental. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Se envía a Escalona Informe de la Comisión Tutelar respecto a la demanda de prórroga de la patria potestad por parte de la madre de D. Juan.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2018-03-02','El CRR de Plasencia informa del ingreso en la UCI del H. Virgen del Puerto de Dª María, tras haber ingeriod una blister de paracetamol.Al parecer faltaban 16 comprimidos pero Carmen no sabe decir cuántos se ha tomado. +++Varios intentos de contacto con la UCI (78605) y con la Unidad de T. Social (78002). +++Llamada a Javier (CRR Plasencia). +++CONTACTO CON UCI: se encuentra CLÍNICAMENTE ESTABLE, pero el riesgo se mantiene hasta PASADAS 48H al menos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2018-03-02','Envío documentación a su abogado, Ángel Sánchez-Cirujano Sánchez, 924243307-609585612, asanchezcirujano@gmail.com, para que presente demanda de modificación de medidas, en relación co la pensión de alimentos a su exmujer.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2018-03-05','(Pedro)Conversación con fernando, T. Soc. H. Virgen del Puerto de Plasencia (78607): +++Remiten por fax Informe de Alta en UCI. +++No he podido contactar directamente con la UCI. +++Fernando comenta que la llamada de ayer (domingo) sería para comunicar el alta en UCI y su paso a planta. También llamaron el sábado. +++Consultará en qué situación de sencuentra Carmen en estos momentos y nos lo dirá. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE ANTONIO'and edp.apellido1='MARTIN'and apellido2='MARTIN'),'2018-03-01','(Pedro) Visita a José Antonio en el CSS Plasencia. +++Pendiente de acceso a plaza de discapacidad. +++Comenta que SU PADRE, con quien salió a comer en su visita del día 28 de febrero, QUERÍA HABLAR CON NOSOTROS, pero que no lo conseguía. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conversación con D. José Antonio, padre de José A: +++"Es un mentiroso. Si yo hubiese querido hablar con ustedes ya lo habría hecho por un medio o por otro. Lo que pasa es que él se quiere marchar de allí porque dice que no está agusto. YO LO VEO ESTUPENDAMENTE, lo atienden bien tiene todo lo que necesita. Si necesitara algo ya me pondría yo en contacto con ustedes que para eso son sus tutores..."','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAIRO'and edp.apellido1='PUERTAS'and apellido2='MARTIN'),'2018-03-01','(Pedro)Visita a Jairo en el CSS de Plasencia. +++Hacía un par de semanas que solicitaba se le fuese a ver desde la Comisión Tutelar y se mostró contento y agradecido por la visita. +++Su percepción de la realidad condiciona enormemente su situación. No tiene afición alguna ni paricipa en ninguna de las actividades que se le proponen y, a pesar de que dice llevarse bien con todo el mundo en el Centro, lo cierto es que no mantiene relación con ninguno de sus compañeros. Se considera un "ser excepcional", carente de conciencia alguna de su patología, que considera superada. Su deseo de lograr el acceso a la Universidad es solo eso, un deseo, ya que a pesar de haber estado matriculado en la academia para prepararlo, a penas ha ido a clase. +++En el CSS no se sabe qué intervención tener con él dadas las dificultades expuestas. Además refieren también ciertas alteraciones de conducta que él mismo niega durante la visita.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JULIAN'and edp.apellido1='GUTIERREZ'and apellido2='RONCERO'),'2018-03-05','(Pedro)Llamada de Julián interesándose por la venta del piso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='RAMON'and edp.apellido1='GILES'and apellido2='SALAZAR'),'2017-09-20','Recibida puntuación de ingreso en Centros de personas con discapcaiadd cone l resultado de NO APTO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='DELGADO'and apellido2='MOTIÑO'),'2018-03-05','-AMALIA .:Después de la ultima visita con su hija , el dia 1 , realizo las siguientes intervenciones: - Envio a Futuex para averiguar deudas pendientes en OAR , vehiculos no dados de baja en trafico y cita en SSB para pedir bono social de la luz y minimos vitales ( dentadura, bomba agua , factura luz pendientes... )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-03-05','Envío de carta para contactar con Ildefonso. Dada la imposibilidad de poder comunicarnos con usted de modo alguno y dado que esta Comisión Tutelar de Adultos desconoce su paradero actual, le rogamos se ponga en contacto con la misma, a la mayor brevedad posible, al objeto de tratar con usted temas de su máximo interés. Dicho contacto lo puede efectuar por los siguientes medios: o Teléfonos….: 924-006057, 924-006030, 924-006085 y 924-008548. o Fax…………….:924-003194 o Correo-e…...:ctutelar@ salud-juntaex.es con la finalidad de fijar fecha y hora para poder mantener una reunión con usted, a ser posible, en la sede de la Comisión Tutelar de Adultos sita en la Avda. de Las Américas nº 4, 1ª planta, en Mérida.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARGARITA'and edp.apellido1='ANTICH'and apellido2='ARROYO'),'2018-03-01','(Pedro)Visita a Margarita en el CSS. +++Tienen previsto iniciar visita de Margarita al Hogar "San Vicente de Paul", como medida de acercamineto progresivo hasta su ingreso en dicho Centro. +++Margarita, auqnue se encuentra muy bien en el Centro Sociosanitario, comprende que su lugar no es un recurso hospitalario y acepta querer probar en este nuevo recurso. +++Llegado el momento, avisarán para ver la posinbilidad de acompañar a Margarita el día del ingreso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2018-03-05','-AMALIA: SE PIDE A PNC CDO. DE SER BENEFICIARIO DE PNC , SE LE ENVIARÁ AL CRR DE CACERES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA ANTONIA'and edp.apellido1='FERNANDEZ'and apellido2='SALGUERO'),'2018-03-05','Llamamos a NAtividad, la hermana de Antonia, dice que el cambio de titularidad del terreno que aparece en el catastro es de hace tiempo. Su madre lo vendió en vida. Todo ha sido un malentendido. Le indicamos que se está gestionando la herencia.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2017-10-05','(Pedro)Llamada de María, T. Soc. SSB de Vva. del Fresno (924-427000/250 y 924-427046. También 625-029064 y 648-185078) (Correo-e: >ssasb.vdelfresno@gmail.com>) +++Requiere información sobre la tutela porque se va a celebrar el juicio de remoción proximamente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CANDIDO'and edp.apellido1='BAS'and apellido2='GONZALEZ'),'2017-10-05','BAJA No obsante el punto anterior, se procede a dar la baja hasta el posible nombramiento. Todo ello porque la misma se debió haber realizado con f/ 02/04/2013. Se incapacitó a D. Candido, y se nombró tutor a su hermana (Dña. Josefa Bas Glez.), mediante Sentencia 42/13, de 2 de abril, proc. Inc. 953/12.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTIN'and edp.apellido1='POZO'and apellido2='CANSECO'),'2018-03-05','(Pedro)Inma Confirma que desde el H. Don Benito-Vva necesitan que preserncialmente alguien de la Comisión acuda el día 8 de marzo a la consulta de pre-anestesia para inforemar. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Intento en varias ocasiones hablar con la DRa. Bernalde (prenestesia), extensión 86693, sin ser posible la comunicación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FRANCO'and apellido2='JIMENEZ'),'2018-03-06','-AMALIA: NOS LLEGA UN COMUNICADO DE P.ORFANDAD . CONFIRMO CON ELLOS QUE SU P.OR.ABS DE 679€/ MES , ESTÁ ACTUALIZADA CON EFECTOS EC. DEL 01/01/18 , NO HAY NADA MÁS QUE ENVIAR. CON RESPECTO A LA PFHC QUE PERCIBIA LA TIENE SUSPENDIDA DESDE EL 2016 QUE FALLECIÓ SU MADRE Y TUTORA . DADO QUE TIENE AHORRADO UNOS 27000€ Y NO PAGA PLAZA RESIDENCIAL , SOLIICTO AL CRR PLASENCIA UN EXTRACTO DE GASTOS PARA VALORAR SI SE SOLICITA O NO LA PF.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUSTO'and edp.apellido1='HERNANDEZ'and apellido2='CASTAÑO'),'2018-03-06','-AMALIA: HABLO CON JAVIER , PSICOLOGO DE ASINDI , NOS INFORMA QUE JUSTO VA A PARTICIPAR EN UN PROYECTO DE EMPLEO , CON FORMACIÓN Y PRACTICAS . DAMOS NUESTRA CONFORMIDAD . PERCIBIRÁ UNA GRATIFICACIÓN DE UNOS 200€ , LE PIDO QUE ME ENVIE JUSTIFICANTE PARA COMUNICARLO A PNC POR SI AFECTA A SU PRESTACIÓN. LO CONSULTARÉ CON PNC CUANDO ME LO ENVIE.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JAVIER'and edp.apellido1='RUBIO'and apellido2='GONZALEZ'),'2018-03-06','Teléfonos de la madre de Javier: 663-863120 y 927-369231','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VALENTIN'and edp.apellido1='POZO'and apellido2='CANSECO'),'2018-03-06','(Pedro) Conversación con la Dra. Hurtado (Preanestesia) (86693): +++No es necesario que se desplace nadie de la Comisión, basta con enviar la acreditación de la persona que figura como tutora: sentencia y aceptación del cargo. +++Acudir con todos los informes médicos disponibles y con analítica completa y electro reciente.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='DAVID'and edp.apellido1='VITA'and apellido2='GIL'),'2018-03-06','-AMALIA: SOLICITAMOS BAJA EN C.O. APROSUBA 6 MIENTRES DURE EL CURSO DE FORMACIÓN , LUEGO SE PROCEDERÁ AL ALTA , NOS LO COMUNICARÁN DESDE EL CENTRO','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='FELIX'and edp.apellido1='FIGUEROA'and apellido2='MARTIN'),'2018-03-06','-ENVIO CDO A CRR CACERES','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA CARMEN'and edp.apellido1='SOLANA'and apellido2='CHANCLON'),'2018-03-06','(Pedro)Conversación con Javier (CRR): +++Desde el domingo está en UHB para valorar la situación que este intento autolítico ha generado, y que no tiene antecedentes desde que se encuentra en CRR (la madre dijo a Javier que cuando estaba con ella ya era dada a tomar pastillas por su cuenta que obligaban a acudir a Urgencias para valoración). +++Se encuentra perfectamente en estos momentos, apenada y pidiendo disculpas por lo que ha hecho. +++No ha habido ninguna manifestación previa que pudiera sugerir esta conducta. A lo único que parece poderse achacar esta situación es al hecho que su pareja tuvo que ingresar en UME y no quiso recibir visitas de nadie en dicha situación.NO QUEDAN SECUELAS DE NINGÚN TIPO. +++Psiquiatra: Dr. Valenzuela.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANGEL JESUS'and edp.apellido1='RODRIGUEZ'and apellido2='MURILLO'),'2018-03-26','SALIDA Entre el 29/03/2018 y el 30/03/2018. Visita a su hermana en Jerez de los Caballeros.','2');
