insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BLAS'and edp.apellido1='GUERRERO'and apellido2='ASEGURADO'),'2018-03-09','SALIDA El 09/03/2018. Viaje a Badajoz para asistir a la Feria del Mayor en el IFEBA. Se parte del centro a las 11:00 Hs. y se regresa, desde badajoz, a las 18:00 Hs.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='HERMENEGILDO'and edp.apellido1='RUIZ'and apellido2='ROMERO'),'2018-02-20','FUGA El 20/02/2018. Sobre las 10:15 Hs.. Se interpone la correspondiente denuncia alrededor de las 14:18 Hs. ante el cuartel de la Guardia Civil.********************************Se ponen en contacto con el centro desde el Hospital de Don Benito-Villanueva para comunicar que el residente se encuentra allí en estado de embriaguez. Van el chofer y dos auxiliares a recogerle pero cuando llegan al hospital se había fugado.*************La madre de hermenegildo llama al centro para comunicar que se ha presentado en su casa, en Cabeza del Buey.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='GRUESO'and apellido2='JIMENEZ'),'2018-02-25','TRASLADO El 25/02/2018. Se comunica a esa Comisión Tutelar de Adultos que el intero José..., ingresado en este Centro y tutelado por esa Comisión, será trasladado al Hospital de Mérida.','2');
