insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='GALLEGO'and apellido2='CALDERON'),'2018-03-07','-AMALIA: NOS ESCRIBE LA TS DE LA R.M. SIERRA PINAR DONDE RESIDE MARIA. SU SOBRINO QUE LA VISITA UNA VEZ AL AÑO PIDE QUE SE LE TRAMITE PLAZA PUBLICA. ACTUALMENTE ESTÁ EN PLAZA PRIVADA POR LA QUE SE ABONO 1440€. DE SUS INGRESOS ( PENSION+P.VINCULADA+ALQUILER VVDA) ABONAMOS 1143 , EL RESTO UTILIZAMOS SU DINERO AHORRADO . MANTIENE 16000€ AHORRADO Y PARA NO DESARRAIGAR Y PUESTO QUE SU ADAPTACION EN LA R.M. ACTUAL ES BUENA , SEGUIREMOS EN PLAZA PRIVADA MIENTRAS PODAMOS SEGUIR PAGANDOLA .ES PROPIETARIA DE UNA VIVIENDA QUE EN ULTIMO TÉRMINO TB PODRIAMOS VENDER. CON LOS AHORROS DE 16000€ TENEMOS PARA 4 AÑOS . MARIA TIENE YA 92 AÑOS.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN GABRIEL'and edp.apellido1='SOBRINO'and apellido2='TARDIO'),'2018-03-07','Envío a Abogacía General citación para comparecer en el Juzgado de 1ª. Instancia e Instrucción nº 5, de Cáceres, en relación con la reintegración de la capacidad para votar de Juan Gabriel.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2018-03-07','(Pedro)Llamada de Vanesa (622294398). +++Está en Miajadas viviendo con su madre en un piso de alquiler. +++Quiere que dejemos de pagar la plaza del piso de Almoharín, pero no sabemos el tiempo que va a permanbecer con su madre, arriesgándonos nuevamente a que se quede en la calle otra vez. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Intento hablar con José Antonio sin conseguirlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GERMAN JOSE'and edp.apellido1='MONTERO'and apellido2='MORENO'),'2018-03-07','(Pedro)Conversación con Ana García, T. Soc. SSB de Plasencia. (600-449238). Correo-e:agarcia@aytoplasencia.es +++Envía convocatoria Comisión Sociosanitaria para el día 15 de marzo a las 13:30. Se le explica que poco puede aportar la Comsión en dicha reunión, dado que ya se están llevando a cabo todos los trámites para que Germán ingrese en un Centro, a ser posible en Placeat. Repecto de la madre, si consideran que la situación se puede calificar de "desprotección" han de comunicarlo a Fiscalía para que valore la apertura de procedimiento de incapacitación.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='PAULA'and edp.apellido1='SOLANA'and apellido2='GUERRA'),'2018-03-08','(Pedro)Intento hablar con la Dra. Victoria Carrasco, C. Salud de Aldea Moret. +++Victoria se ha trasladado a Cañaveral desde enero. +++Médica de Familia actual (no titular), Dra. Rita Coral Almaraz. +++Hablo con Administrativo para que deje mensaje a Valentina y me llame. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamada de Valentina, T. Soc. C.Salud Aldea Moret (52515). +++Paula ha estado con la DRa. Rita el 23 y 28 de febereo y el día 22 de febereo estuvo en el PAC. +++Valnetina tampoco cree que un ingreso en Centro sea necesario, ya que los factores son de carácter socila más que méidco. +++PRIORIDADES de la Ctaex: control diabetes (no insulino dependiente), asistencia a ESM (si bien su "trastorno" de identidad no afecta a su autonomía personal y queun posible ingreso en centro pueda descenadenar en ella una desetabilización clínica importante: cuando ingresó su hermana pensaba que la habían secuestrado un grupo de conspiradores... +++Al parecer hahabido quejas de los vecinos desde hace un tiempo. +++Valentina se ofrece para visitar a los vecinos y hablará con la DRa. Rita sobre Paula, a ver cuál es su criterio. Enviará informes sobre ello.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2018-03-08','(Pedro) Conversación con José Antonio. Intento la llamada pero no me coge el teléfono.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2018-03-08','(Pedro)Llamada de Carmen, T. Soc. del ESM Valdepasillas (42853). +++María ha estado ingresada en el H. Infanta en la Unidad de Medicina Interna por problemas hepáticos. Enviará alta.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GERMAN JOSE'and edp.apellido1='MONTERO'and apellido2='MORENO'),'2018-03-07','- SE TRAMITA PFHC +CPTO ATP , LA TIENE SUSPENDIDA DESDE EL CAMBIO DE TUTOR . NO PUEDO PEDIR PNC PQ A DIA DE HOY SIGUE EN EL DOMICILIO FAMILIAR Y LAS RENTAS FAMILIARES PODRIAN PERJUDICARLE. CUANDO INGRESE EN CENTRO SE VALORARÁ PEDIR PNC + CPTO. NO SE PUDO TRAMITAR EN EL TRIMESTRE ANTERIOR PQ EL INVENTARIO NO ESTABA TERMINADO Y HABIA QUE ABRIR CUENTA NUEVA. UNA VEZ FIRMADO TODA LA DOCUMENTACION SE ENVIARÁ AL INSS CACERES.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='CONCEPCION'and edp.apellido1='ALEJANDRO'and apellido2='DIAZ'),'2018-03-08','(Pedro)Visita concertada con Concepción, acompñada de Gisela (CRR): +++Se abonará por, última vez, los dos recibos de agua que su madre tiene PDTES. de pagar (POR ÚLTIMA VEZ). +++Solicita aumento de los gastos de bolsillo, pero de acuerdo con el CRR se cosnidera que dicho aumento no es necesario. +++SE le propone, para esas "invitaciones" que quiere hacer, que ahorre un poquito del dinero que tiene. +++SE le proporciona el Teléfono del Mayor para que se lo dé a su madre, quien se plantea solicitar residencia de mayores (83 años), además de indicarle que acuda asl SSB de su zona para solicitarlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ANTONIO'and edp.apellido1='FERRERA'and apellido2='CAMBERO'),'2018-03-08','-AMALIA: SOLICITADA LEY DEPENDENCIA .','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='GERMAN JOSE'and edp.apellido1='MONTERO'and apellido2='MORENO'),'2018-03-08','(Pedro)Conversación con Domingo, Director Cadex Cáceres (21998). +++Germán se encuentra en el puesto número 4 para ser citado, lo que supone que será llamado a finales de abril o primeros de mayo. +++Envío correo-e al Cadex justificando urgencia del caso.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='EUGENIO'and edp.apellido1='RANGEL'and apellido2='MONROY'),'2018-03-08','-AMALIA : ES PERCEPTOR DE PNC ( 304€) Y P. ORFANDAD ( 2734€ ANUAL )','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='VANESA'and edp.apellido1='FERNANDEZ'and apellido2='GOMEZ'),'2018-03-09','(Pedro)Conversación con Ana Isabel, T. Soc. SSB de Miajadas (927-347000). +++No ha tenido contacto con Vanesa. No obstante, comprobará si está empadronada en Miajadas y si sabe algo nuevo nos lo dirá. +++Confirma que la señora que aparece en el fax que remitió ayer Vanesa para pagar el alquiler (Dª María Masa Franco) tiene dos pisos en alquiler. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Conveerscaión con Vanesa: +++El piso de alquiler está en la calle Donoso Cortés 23, 2º de Miajadas. +++El conmtrato está a nombre de su madre, Dª Mª Estrella Gómez Sánchez (DNI 28943409-W). Teléfonos 669147754. +++La madre no está trabajando ahora y parece ser que se va a ir a Trujillo a cuidar a los abuelos. Ha hablado con la casera para que el psio se lo quede Vanesa cuando se vaya. +++Se le indica a Vanesa que ella no puede firnar ningún contrtao y que si quiere pagar ella el piso tiene que estar a su nombre. DEBE ENVIAR A LA COMSIÓN ESE CONTRATO PARA SU ESTUDIO Y VALORAR EL ALQUILER COMO ALTERNATIVA. +++Bajo ningún concepto está dispuesta a volver al Piso tutelado de Almoharín: "Puedo paagar el alquiler y con 50€ paso el mes..." +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++Llamo a la madre de Vanesa: el primer teléfono es de una farmacia y el segundo comunica. ++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++PENDIENTE HABLAR CON JOSÉ ANTONIO.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='TOMAS'and edp.apellido1='GONZALEZ'and apellido2='JIMENEZ'),'2018-03-09','Alberto me entrega hoy una documentación de la Agencia Tributaria, que tuvo entrada en el registro del Sepad el 6/2/2018. En esta documentación le reclaman 378 euros, en concepto de iva, por el alquiler de un local arrendado a Macamacris S.A., por Isabel González Hormeño, fallecida el día 8/5/2015. Parece que existe algún tipo de relación sucesoria entre Tomás y esta señora, motivo por el que le reclaman el 25%. En esta documentación daban un plazo de 10 días hábiles para alegar, que ya han pasado. ------------------------------------------------------------Me pongo a hacer averiguaciones llamando a su hermana Isabel, en el 651923139. Hablo con ella y me dice que Isabel González Hormeño es su madre. Me dice que aún no se ha hecho la herencia y que si, tenía alquilado ese local a esa empresa, pero que no sabe. Que ella no ha recibido la misma carta que Tomás, reclamándole el iva de ese local. Que quien sabe más de todo es su hermano mayor, Pascual (927367079). Que son 4 hermanos.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JUAN'and edp.apellido1='CHAMORRO'and apellido2='HOLGUIN'),'2018-03-09','(Pedro)Conveersación con C. Salud de Guadalupe: +++Clara (T. SOc.): lunes y jueves en Guadalupe.Viernes en Logrosán. +++Dra. Consolación: llamar a partir de la 11:15h.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MANUEL'and edp.apellido1='CONTADOR'and apellido2='MATEOS'),'2018-03-09','Iciar: Llamo a la inmobiliaria de Badajoz -Urbaniza2- pero el apartamento que le gustaba a Manuel ya ha sido alquilado. Nos ponemos en contacto con Tony de Futuex para que sigan buscando piso para él con +- las mismas condiciones de precio. Cuando tengan alguno que se ajuste nos mandarán las referencia a la Comisión antes de que Manuel se pase a verlo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE FLORENCIO'and edp.apellido1='GONZALEZ'and apellido2='MANGAS'),'2018-03-09','(Pedro)Conversación con Dª Luisa (madre) y José Florencio: +++A petición de Dª Luisa, se concieta reunión en la CTAEx para el próximo día 15 de marzo, jueves. No se puede cerrar la hora porque no sabe el horario del autobús. +++Avisará si no pudiera venir por algún motivo.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MARIA'and edp.apellido1='MURILLO'and apellido2='DELGADO'),'2018-03-09','(Pedro)Lllamada de Carmen, T. Soc. ESM: +++Envía por fax documentación clínica. +++Influida por Antonio FReire, su compñaero, ha cambiado de Médico de familia para que su Psiquiatra fuera el Dr. Antonio Glez. Glez.(el mismo que el de este compañero). +++El Dr. Samino vio a María con su madre, por la calle, paseando con su perro y de manera tranquila y apacible.Este mismo día la vio en consulta administrativa.','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='BEATRIZ'and edp.apellido1='MEJIAS'and apellido2='DE LA MORENA'),'2018-03-12','Iciar: Llama la madre de Beatriz- tlf. 642026518 - para decir que el jueves 15 de marzo a las 8am Beatriz tiene una citación en los Juzgados de Badajoz por algún altercado que tuvieron con los vecinos. La madre no tiene la citación en papel dice que le han llamadao del Juzgado de Paz de Calera de León. La Comisión no tiene constancia de este hecho. Llamo al Juzgado de paz -924 584 101-y ellos no tiene tampoco ninguna noticia al respecto. Intenta averiguar en Monasterio y se pondrán en contacto con nosotros','2');
