insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='MIGUEL'and edp.apellido1='GAMERO'and apellido2='GOMEZ'),'2018-03-14','Iciar. llama el hermano - t/c 677248077 - nos comunica que Miguel está ingresado en el Hospial de Mérida desde ayer por la noche con inflamación del hígado. También insiste en la posibilidad de cambiar a su hermano de centro pues, según él, desde que está ingresado en el Sociosanitario de Mérida la evolución de su hermano ha ido a peor. +++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++(Pedro)Llamo al Hospital de Mérida, extensión 82429. Me pasan con Adminitrativo en la 81360. +++Dra. Mª Dolores Hernández Durán (31697): a la exploración, transaminasas altas, hígado agrandado y piedras en vesícula biliar. Van a hacerle una resonancia, para lo cual enviarán por fax consentimineto informado para su firma y posterior remisión al fax de origen. +++Está bajo control de la Unidad de Digestivo, pero dados los intentos de fuga del CSS de Mérida lo han derivado a UHB por requerir mayor control en este sentido. Pero la Unidad de referencia es la de Digestivo. +++ESPECIALISTA DE referencia: Dr BORRALLO (Digestivo)','2');
insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='JOSE MANUEL'and edp.apellido1='ROMERO'and apellido2='MEDIAVILLA'),'2018-03-14','(Pedro)Llamada de D. José Luis Romero Mediavilla (687-581061), hermano de José Manuel. +++Su hermano se ha presentado en su casa, pero dice que él no está para vivir solo, opinión que comparte esta Comsión, si bien de su nueva situación solo él es el responsable al haber pedido EL ALTA VOLUNTARIA del CRR. +++Comenta que quiere pedir ingreso voluntario en Psiquiatrico de Plasencia. +++De vez en cuando le dan dinero y ahora dice que quiere dar de alta el agua y la luz en el psio, que según D. José Luis no está en condiciones de ser habitado. +++++++++++++++++++++++++++++++++++++++Conversación con Javier pecero, CRR de Mérida. +++Han comunicado al juzgado que D. José manuel ha pedido el alta voluntaria del CRR y que, por lo tanto, la pena que iba a cumplir en el centro no la puede cumplir allí. Esto puede dar lugar a que se considere quebrantamineto de condena...','2');
