insert into historial_expedientes(expediente_id,fecha_suceso,descripcion,is_deleted) values((select ei.id from expedientes_intranet ei inner join expediente_datos_personales edp on edp.id=ei.expediente_datos_personales_id where edp.nombre='ILDEFONSO'and edp.apellido1='GARCIA'and apellido2='RODRIGUEZ'),'2018-03-16','(Pedro)Llamada de María,, ESM de Zafra. Está Ati con ella. Le pido que me pase con él. +++CONCERTAMOS REUNIÓN CON ÉL para el próximo martes, 20 de marzo, a las 10.00h. +++Dice no tener teléfono de contacto. +++DIRECCIÓN ACTUAL (ALQUILER): Edificio ABRIL, Avda. de la Estación nº 14, Puerta A, 2ºD. 06300 ZAFRA. +++TRERÁ CONTRATO DE ALQUILER. +++Dice compartirlo con dos amigos, a los cuales quiere echar porque le están perjudicando. +++Acude normalmente a CEDEX Zafra y al ESM.','2');
